ST.xhtml:
F_RaiseAlarm := FALSE;
IF id = 0 THEN RETURN; END_IF
FOR i := 0 TO 63 DO
    IF GVL_Alm.aActive[i].active AND (GVL_Alm.aActive[i].id = id) THEN
        RETURN;                      // already active
    END_IF
END_FOR
FOR i := 0 TO 63 DO
    IF NOT GVL_Alm.aActive[i].active THEN
        GVL_Alm.aActive[i].id     := id;
        GVL_Alm.aActive[i].class  := class;
        GVL_Alm.aActive[i].tsS    := GVL_Sts.uptimeS;
        GVL_Alm.aActive[i].active := TRUE;
        GVL_Alm.aActive[i].acked  := FALSE;
        // history ring
        GVL_Alm.aHistory[GVL_Alm.histHead] := GVL_Alm.aActive[i];
        GVL_Alm.histHead := (GVL_Alm.histHead + 1) MOD 200;
        F_RaiseAlarm := TRUE;
        RETURN;
    END_IF
END_FOR

dtS := CycleMs / 1000.0;
rtHome(CLK := HomeExec);
rtMove(CLK := MoveExec);
rtReset(CLK := ResetExec);

IF Abort THEN
    state := 0; Busy := FALSE;
    tonTO(IN := FALSE);
END_IF

IF rtReset.Q THEN
    Error := FALSE; ErrorID := 0;
END_IF

IF Sim THEN
    // ---------------- SIMULATION MODEL ----------------
    Sts.powered := Enable;
    CASE state OF
        0: // idle
            IF Enable AND rtHome.Q THEN
                state := 1; simHomeT := 0.0; Busy := TRUE; Done := FALSE;
            ELSIF Enable AND Sts.homed AND rtMove.Q THEN
                simTgt := TargetPos; state := 2; Busy := TRUE; Done := FALSE;
                tonTO(IN := FALSE);
            ELSIF Enable AND (NOT Sts.homed) AND rtMove.Q THEN
                Error := TRUE; ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_NOT_HOMED);
            END_IF
        1: // homing
            simHomeT := simHomeT + dtS;
            IF simHomeT >= SimHomeS THEN
                simPos := 0.0; Sts.homed := TRUE;
                state := 0; Busy := FALSE; Done := TRUE;
            END_IF
        2: // moving: constant-velocity approach
            stepMax := Vel * dtS;
            IF ABS(simTgt - simPos) <= stepMax THEN
                simPos := simTgt;
                state := 0; Busy := FALSE; Done := TRUE;
            ELSIF simTgt > simPos THEN
                simPos := simPos + stepMax;
            ELSE
                simPos := simPos - stepMax;
            END_IF
            tonTO(IN := TRUE, PT := GVL_Cfg.TO_AXIS_MOVE);
            IF tonTO.Q THEN
                state := 0; Busy := FALSE; Error := TRUE;
                ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_TIMEOUT);
            END_IF
    END_CASE
    IF StopExec THEN state := 0; Busy := FALSE; END_IF
    Sts.actPos := simPos;
    Sts.inPos  := (state = 0);
ELSE
    // ---------------- REAL HARDWARE (SoftMotion) ----------------
    mcPower(Axis := Axis, Enable := Enable, bRegulatorOn := Enable, bDriveStart := Enable);
    Sts.powered := mcPower.Status;

    mcHome(Axis := Axis, Execute := (rtHome.Q OR mcHome.Busy) AND NOT Abort, Position := 0.0);
    IF mcHome.Done THEN Sts.homed := TRUE; END_IF

    mcMove(Axis := Axis,
           Execute      := (rtMove.Q OR mcMove.Busy) AND NOT Abort AND NOT StopExec,
           Position     := TargetPos,
           Velocity     := Vel,
           Acceleration := Acc,
           Deceleration := Acc);

    mcStop(Axis := Axis, Execute := StopExec OR Abort, Deceleration := Acc * 2.0);
    mcReset(Axis := Axis, Execute := rtReset.Q);

    Busy := mcHome.Busy OR mcMove.Busy;
    IF mcHome.Done OR mcMove.Done THEN Done := TRUE; END_IF
    IF rtHome.Q OR rtMove.Q THEN Done := FALSE; END_IF

    IF mcMove.Error OR mcHome.Error OR mcPower.Error THEN
        Error := TRUE;
        ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_DRIVE);
        Sts.homed := FALSE;              // demand re-home after drive fault
    END_IF
    Sts.actPos := Axis.fSetPosition;     // TODO: use MC_ReadActualPosition if preferred
    Sts.inPos  := NOT Busy;
END_IF

IF NOT Sts.powered THEN Sts.homed := FALSE; END_IF   // power loss clears homed
Sts.errorId := ErrorID;

// ---- acquire temperature ----
IF Sim THEN
    simC := simC + (SIM_GAIN * outPct / 100.0 - (simC - 25.0) / SIM_TAU)
                 * (CycleMs / 1000.0) * GVL_Cfg.SIM_TIME_SCALE;
    actC := simC;
ELSE
    actC := TO_LREAL(iTempRaw) / 10.0;
END_IF

// ---- TC plausibility (real only) ----
IF NOT Sim THEN
    IF (actC < -20.0) OR (actC > 400.0) THEN tcFaultCnt := tcFaultCnt + 1; ELSE tcFaultCnt := 0; END_IF
    IF ABS(actC - lastC) > GVL_Cfg.TC_RATE_MAX * (CycleMs / 1000.0) * 10.0 THEN
        tcFaultCnt := tcFaultCnt + 1;
    END_IF
    IF tcFaultCnt > 25 THEN
        Error := TRUE;
        ErrorID := F_Err(GVL_Cfg.SS_HEAT_0 + TO_UINT(ZoneId), GVL_Cfg.ERR_TC);
    END_IF
END_IF
lastC := actC;

// ---- PI @100 ms ----
divCnt := divCnt + 1;
IF divCnt >= 5 THEN
    divCnt := 0;
    ramping := (SetC - actC) > 20.0;
    IF Enable AND NOT Error AND (StaggerToken OR NOT ramping) THEN
        err := SetC - actC;
        integ := LIMIT(0.0, integ + err * GVL_Cfg.HEAT_KI * dtPi * 100.0, 100.0);
        outPct := LIMIT(0.0, GVL_Cfg.HEAT_KP * err + integ, 100.0);
    ELSE
        outPct := 0.0; integ := 0.0;
    END_IF
END_IF

// ---- time-proportioned SSR ----
pwmT := pwmT + CycleMs;
IF pwmT >= GVL_Cfg.PWM_WINDOW_MS THEN pwmT := 0.0; END_IF
qSsr := Enable AND NOT Error AND (pwmT < outPct / 100.0 * GVL_Cfg.PWM_WINDOW_MS);

Zone.setC := SetC;   Zone.actC := actC;   Zone.outPct := outPct;
Zone.tcOk := NOT Error;
Zone.atSet := ABS(SetC - actC) <= GVL_Cfg.HEAT_AT_BAND;
Zone.enabled := Enable;

qValve := Cmd;
IF Cmd <> lastCmd THEN
    simT := 0.0;
    lastCmd := Cmd;
END_IF

IF Sim THEN
    simT := simT + CycleMs / 1000.0;
    IF simT >= SIM_TRAVEL_S THEN simExt := Cmd; END_IF
    extEff := simExt;  retEff := NOT simExt;
ELSE
    extEff := iExtended; retEff := iRetracted;
END_IF

IF extEff AND retEff THEN                 // both sensors -> wiring fault
    Error := TRUE; ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_SENSOR);
END_IF

Extended  := extEff AND NOT retEff;
Retracted := retEff AND NOT extEff;
Moving    := NOT Extended AND NOT Retracted;

tonTO(IN := (Cmd AND NOT Extended) OR (NOT Cmd AND NOT Retracted), PT := GVL_Cfg.TO_PNEU);
IF tonTO.Q THEN
    Error := TRUE; ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_TIMEOUT);
END_IF

rtExec(CLK := PathExec);
qEnable := Enable;

// effective InPos: sim model or hardware input
IF Sim THEN
    inPosEff := (state <> 3) OR (simTimer >= SIM_TRAVEL_S);
ELSE
    inPosEff := iInPos;
END_IF

IF Abort THEN
    state := 0; Busy := FALSE; qCtrg := FALSE;
    tonTO(IN := FALSE);
END_IF

IF (NOT Sim) AND iAlarm THEN
    Error := TRUE; ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_DRIVE);
    state := 0; Busy := FALSE; qCtrg := FALSE;
    pInit := FALSE;   // drive may have power-cycled: RAM PR table reverts to
                      // EEPROM, so force a full re-push on the next profile
END_IF

CASE state OF
    0: // idle
        qCtrg := FALSE;
        IF Enable AND rtExec.Q AND (PathNo >= 0) AND (PathNo <= 2) THEN
            latched := PathNo;
            qSel0 := (latched MOD 2) = 1;
            qSel1 := ((latched / 2) MOD 2) = 1;
            state := 1; Busy := TRUE; Done := FALSE;
            sawMoving := FALSE; simTimer := 0.0;
            tonTO(IN := FALSE);
        END_IF
    1: // one full cycle DO settle before CTRG (drive DI filter)
        state := 3;
        qCtrg := TRUE;                     // held high for whole move
    3: // executing: wait saw-moving handshake
        simTimer := simTimer + CycleMs / 1000.0;
        IF NOT inPosEff THEN sawMoving := TRUE; END_IF
        tonTO(IN := TRUE, PT := GVL_Cfg.TO_PRESS);
        IF inPosEff AND (sawMoving OR (Sim AND simTimer >= SIM_TRAVEL_S)) THEN
            qCtrg := FALSE; ActPath := latched;
            state := 0; Busy := FALSE; Done := TRUE;
            tonTO(IN := FALSE);
        ELSIF tonTO.Q THEN
            qCtrg := FALSE;
            state := 0; Busy := FALSE; Error := TRUE;
            ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_TIMEOUT);
        END_IF
END_CASE

// ============================================================
// PR path table parameter writer (positions only; motion stays DI).
// SIM: accepted instantly. HARDWARE: closed-loop Modbus RTU write ->
// readback verify -> retry (pattern proven on the old Z-axis rig).
// Only call while press idle; FB_Press guarantees this.
// ============================================================
rtWr(CLK := WriteParams);
IF rtWr.Q AND (pStep = 0) THEN
    ParamsValid := FALSE; ParamErr := FALSE; ParamBusy := TRUE;
    pRetry := 0; pStep := 1;
END_IF
MbSlave := TO_WORD(SubsysId - GVL_Cfg.SS_PRESS_0 + 1);   // press n -> RS485 slave n+1

CASE pStep OF
    0: ;
    1: // route: skip if drive already holds these values
        IF pInit AND (OpenPosMm = shadowOpen) AND (SmashPosMm = shadowSmash)
                 AND (HoldPosMm = shadowHold) THEN
            ParamsValid := TRUE; ParamBusy := FALSE; pStep := 0;
        ELSIF Sim AND NOT GVL_Cfg.PRESS_MB_REAL THEN
            // pure simulation: accept instantly
            shadowOpen := OpenPosMm; shadowSmash := SmashPosMm; shadowHold := HoldPosMm;
            pInit := TRUE;
            ParamsValid := TRUE; ParamBusy := FALSE; pStep := 0;
        ELSE
            pIdx := 0; pStep := 2;                        // real Modbus push
        END_IF
    2: // compose register write pIdx: path (pIdx/2), high/low word (pIdx MOD 2)
        CASE (pIdx / 2) OF
            0: pPosMm := OpenPosMm;
            1: pPosMm := SmashPosMm;
            2: pPosMm := HoldPosMm;
        END_CASE
        pPulses := TO_DINT(pPosMm * GVL_Cfg.PRESS_PULSES_PER_MM);
        IF (pIdx MOD 2) = 0 THEN
            MbAddr  := GVL_Cfg.MB_PR_BASE + TO_WORD(pIdx / 2) * GVL_Cfg.MB_PR_BLOCK + GVL_Cfg.MB_PR_POSH;
            MbValue := TO_WORD(SHR(TO_DWORD(pPulses), 16) AND 16#FFFF);
        ELSE
            MbAddr  := GVL_Cfg.MB_PR_BASE + TO_WORD(pIdx / 2) * GVL_Cfg.MB_PR_BLOCK + GVL_Cfg.MB_PR_POSL;
            MbValue := TO_WORD(TO_DWORD(pPulses) AND 16#FFFF);
        END_IF
        MbWrExec := TRUE; tonMb(IN := FALSE);
        pStep := 3;
    3: // wait transport ack (LS_ModbusMasterlib glue answers MbWrDone/MbWrErr)
        tonMb(IN := TRUE, PT := T#1S);
        IF MbWrDone THEN
            MbWrExec := FALSE; tonMb(IN := FALSE); pRetry := 0;
            pIdx := pIdx + 1;
            IF pIdx > 5 THEN
                shadowOpen := OpenPosMm; shadowSmash := SmashPosMm; shadowHold := HoldPosMm;
                pInit := TRUE;
                ParamsValid := TRUE; ParamBusy := FALSE; pStep := 0;
            ELSE
                pStep := 2;                               // next register (fresh exec edge)
            END_IF
        ELSIF MbWrErr OR tonMb.Q THEN
            MbWrExec := FALSE; tonMb(IN := FALSE);
            pRetry := pRetry + 1;
            IF pRetry > P_MAX_RETRY THEN
                ParamErr := TRUE; ParamBusy := FALSE; pStep := 0;
            ELSE
                pStep := 2;                               // resend same register
            END_IF
        END_IF
END_CASE

// TODO(MIGRATION): background Modbus RTU poll <=2 Hz for ActPosMm +
// AlarmCode; failure raises INFO alarm only, never blocks motion.

IF Sim THEN
    Q := SimValue;
ELSE
    IF iRaw = lastRaw THEN
        acc := acc + CycleMs;
        IF acc >= DebounceMs THEN Q := iRaw; END_IF
    ELSE
        acc := 0.0;
        lastRaw := iRaw;
    END_IF
END_IF

cps := GVL_Cfg.ENC_CPR / TO_DINT(GVL_Cfg.STATIONS);
rtHome(CLK := HomeExec);
rtGoto(CLK := GotoExec);

// ------- feedback source -------
IF Sim THEN
    IF qFwd THEN
        stepC := TO_DINT(TO_LREAL(qSpeed) * CycleMs / 20.0);
        simEnc := simEnc + MAX(stepC, 1);
    ELSIF qRev THEN
        stepC := TO_DINT(TO_LREAL(qSpeed) * CycleMs / 20.0);
        simEnc := simEnc - MAX(stepC, 1);
    END_IF
    encEff  := simEnc;
    homeEff := ((simEnc MOD GVL_Cfg.ENC_CPR) + GVL_Cfg.ENC_CPR) MOD GVL_Cfg.ENC_CPR < 60;
ELSE
    encEff  := iEnc;
    homeEff := iHomeProx;
END_IF

IF Abort THEN
    qFwd := FALSE; qRev := FALSE; qSpeed := 0;
    state := 0; Busy := FALSE; tonTO(IN := FALSE);
END_IF

CASE state OF
    0: // idle (pin extended = locked)
        qFwd := FALSE; qRev := FALSE; qSpeed := 0;
        IF Enable AND rtHome.Q THEN
            goingHome := TRUE; state := 10; Busy := TRUE; Done := FALSE;
        ELSIF Enable AND Homed AND rtGoto.Q THEN
            IF (TargetStation < 0) OR (TargetStation >= GVL_Cfg.STATIONS) THEN
                Error := TRUE; ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_BAD_CMD);
            ELSIF TargetStation = ActStation THEN
                Done := TRUE;
            ELSE
                goingHome := FALSE; state := 10; Busy := TRUE; Done := FALSE;
            END_IF
        END_IF

    10: // retract pin
        PinCmd := FALSE;
        tonTO(IN := TRUE, PT := GVL_Cfg.TO_PNEU);
        IF PinRetracted THEN
            tonTO(IN := FALSE); state := 20;
        ELSIF tonTO.Q THEN
            state := 90; ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_PIN);
        END_IF

    20: // rotate
        IF goingHome THEN
            qFwd := TRUE; qSpeed := GVL_Cfg.IDX_SPEED_CREEP;
            tonTO(IN := TRUE, PT := GVL_Cfg.TO_INDEX);
            IF homeEff THEN
                qFwd := FALSE; qSpeed := 0;
                encZero := encEff;
                tonTO(IN := FALSE); state := 30;
            ELSIF tonTO.Q THEN
                state := 90; ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_TIMEOUT);
            END_IF
        ELSE
            tgtCounts := encZero + TO_DINT(TargetStation) * cps;
            diff := tgtCounts - encEff;
            IF Bidirectional THEN
                // shortest signed path within one revolution
                diff := ((diff MOD GVL_Cfg.ENC_CPR) + GVL_Cfg.ENC_CPR) MOD GVL_Cfg.ENC_CPR;
                IF diff > GVL_Cfg.ENC_CPR / 2 THEN diff := diff - GVL_Cfg.ENC_CPR; END_IF
            ELSE
                diff := ((diff MOD GVL_Cfg.ENC_CPR) + GVL_Cfg.ENC_CPR) MOD GVL_Cfg.ENC_CPR;
            END_IF
            fwdDir := diff >= 0;
            qFwd := fwdDir AND (ABS(diff) > GVL_Cfg.IDX_STOP_WIN);
            qRev := (NOT fwdDir) AND (ABS(diff) > GVL_Cfg.IDX_STOP_WIN);
            IF ABS(diff) > GVL_Cfg.IDX_DECEL_WIN THEN
                qSpeed := GVL_Cfg.IDX_SPEED_FAST;
            ELSE
                qSpeed := GVL_Cfg.IDX_SPEED_CREEP;
            END_IF
            tonTO(IN := TRUE, PT := GVL_Cfg.TO_INDEX);
            IF ABS(diff) <= GVL_Cfg.IDX_STOP_WIN THEN
                qFwd := FALSE; qRev := FALSE; qSpeed := 0;
                tonTO(IN := FALSE); state := 30;
            ELSIF tonTO.Q THEN
                state := 90; ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_TIMEOUT);
            END_IF
        END_IF

    30: // extend pin + verify
        PinCmd := TRUE;
        tonTO(IN := TRUE, PT := GVL_Cfg.TO_PNEU);
        IF PinExtended THEN
            tonTO(IN := FALSE);
            IF goingHome THEN
                Homed := TRUE; ActStation := 0;
            ELSE
                // encoder-vs-pin plausibility
                diff := (((encEff - encZero) MOD GVL_Cfg.ENC_CPR) + GVL_Cfg.ENC_CPR) MOD GVL_Cfg.ENC_CPR;
                IF ABS(diff - TO_DINT(TargetStation) * cps) > GVL_Cfg.IDX_VERIFY_WIN THEN
                    state := 90; ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_PIN);
                    Homed := FALSE;                    // demand re-home
                    RETURN;
                END_IF
                ActStation := TargetStation;
            END_IF
            state := 0; Busy := FALSE; Done := TRUE;
        ELSIF tonTO.Q THEN
            state := 90; ErrorID := F_Err(SubsysId, GVL_Cfg.ERR_PIN);
        END_IF

    90: // fault
        qFwd := FALSE; qRev := FALSE; qSpeed := 0;
        Busy := FALSE; Error := TRUE;
        state := 0;
END_CASE

wantF := Enable AND ReqFridgeOpen AND NOT Abort;
wantC := Enable AND ReqChamberOpen AND NOT Abort;

// mutual exclusion: fridge side has priority; never open one until
// the other is CONFIRMED retracted (closed)
IF wantF AND wantC THEN wantC := FALSE; END_IF
DoorFridge.Cmd  := wantF AND DoorChamber.Retracted;
DoorChamber.Cmd := wantC AND DoorFridge.Retracted;

FridgeOpen    := DoorFridge.Extended;
ChamberOpen   := DoorChamber.Extended;
ChamberSealed := DoorFridge.Retracted AND DoorChamber.Retracted;
Busy := (wantF AND NOT FridgeOpen) OR (wantC AND NOT ChamberOpen)
     OR ((NOT wantF) AND NOT DoorFridge.Retracted)
     OR ((NOT wantC) AND NOT DoorChamber.Retracted);

IF DoorFridge.Error OR DoorChamber.Error THEN
    Error := TRUE;
    ErrorID := F_Err(GVL_Cfg.SS_AIRLOCK, GVL_Cfg.ERR_TIMEOUT);
ELSE
    Error := FALSE; ErrorID := 0;
END_IF

// hard invariant — must never trip, in sim or real
IF FridgeOpen AND ChamberOpen THEN
    Error := TRUE;
    ErrorID := F_Err(GVL_Cfg.SS_AIRLOCK, GVL_Cfg.ERR_INTERLOCK);
END_IF

rtExec(CLK := CmdExec);
trayEff := (Sim AND TrayHeld) OR ((NOT Sim) AND iTrayPresent);

// brake proving: release demand vs feedback
qBrakeRelease := Enable AND AxZ.Sts.powered AND NOT Abort AND NOT Error;
brakeChk(IN := (NOT Sim) AND (qBrakeRelease <> iBrakeOk), PT := T#500MS);
IF brakeChk.Q THEN
    Error := TRUE;
    ErrorID := F_Err(GVL_Cfg.SS_FORK_Z, GVL_Cfg.ERR_DRIVE);   // MACHINE_STOP via PRG_Alarms map
END_IF

IF Abort THEN
    iSt := 0; Busy := FALSE;
    AxZ.MoveExec := FALSE; AxT.MoveExec := FALSE;
    AxZ.HomeExec := FALSE; AxT.HomeExec := FALSE;
END_IF
Homed := AxZ.Sts.homed AND AxT.Sts.homed;

tonTO(IN := Busy, PT := GVL_Cfg.TO_MECH);
IF tonTO.Q AND Busy THEN
    iSt := 0; Busy := FALSE; Error := TRUE;
    ErrorID := F_Err(GVL_Cfg.SS_FORK, GVL_Cfg.ERR_TIMEOUT);
END_IF

CASE iSt OF
    0:
        IF Enable AND rtExec.Q AND NOT Error THEN
            Done := FALSE; ErrorID := 0;
            CASE Cmd.code OF
                1:  (* MCMD_HOME *)  iSt := 10; Busy := TRUE;
                20, 21: (* MCMD_FETCH / MCMD_RETURN *)
                    level := TO_INT(Cmd.p1);
                    IF (level < 0) OR (level >= GVL_Cfg.TRAY_LEVELS) THEN
                        Error := TRUE; ErrorID := F_Err(GVL_Cfg.SS_FORK, GVL_Cfg.ERR_BAD_CMD);
                    ELSE
                        fetching := (Cmd.code = GVL_Cfg.MCMD_FETCH);  // constant compare OK outside CASE labels
                        zBase := GVL_Cfg.FORK_Z0 + TO_LREAL(level) * GVL_Cfg.FORK_LEVEL_H;
                        iSt := 20; Busy := TRUE;
                    END_IF
            ELSE
                Error := TRUE; ErrorID := F_Err(GVL_Cfg.SS_FORK, GVL_Cfg.ERR_BAD_CMD);
            END_CASE
        END_IF
    10: // HOME: telescope retract first, then Z
        AxT.HomeExec := TRUE;
        IF AxT.Sts.homed THEN AxT.HomeExec := FALSE; iSt := 11; END_IF
    11:
        AxZ.HomeExec := TRUE;
        IF AxZ.Sts.homed THEN
            AxZ.HomeExec := FALSE; iSt := 0; Busy := FALSE; Done := TRUE;
        END_IF
    20: // Z to level (fetch: exact; return: +microlift so tray clears)
        IF fetching THEN AxZ.TargetPos := zBase;
        ELSE AxZ.TargetPos := zBase + GVL_Cfg.FORK_MICROLIFT; END_IF
        AxZ.Vel := GVL_Cfg.F_VEL; AxZ.Acc := GVL_Cfg.F_ACC;
        AxZ.MoveExec := TRUE;
        IF AxZ.Done THEN AxZ.MoveExec := FALSE; iSt := 21; END_IF
        IF AxZ.Error THEN iSt := 90; END_IF
    21: // telescope out
        AxT.TargetPos := GVL_Cfg.FORK_TELE_OUT; AxT.Vel := GVL_Cfg.F_VEL; AxT.Acc := GVL_Cfg.F_ACC;
        AxT.MoveExec := TRUE;
        IF AxT.Done THEN AxT.MoveExec := FALSE; iSt := 22; END_IF
        IF AxT.Error THEN iSt := 90; END_IF
    22: // micro-lift (fetch) or micro-drop (return)
        IF fetching THEN AxZ.TargetPos := zBase + GVL_Cfg.FORK_MICROLIFT;
        ELSE AxZ.TargetPos := zBase; END_IF
        AxZ.MoveExec := TRUE;
        IF AxZ.Done THEN AxZ.MoveExec := FALSE; iSt := 23; END_IF
        IF AxZ.Error THEN iSt := 90; END_IF
    23: // telescope in
        AxT.TargetPos := GVL_Cfg.FORK_TELE_IN; AxT.MoveExec := TRUE;
        IF AxT.Done THEN
            AxT.MoveExec := FALSE;
            IF fetching THEN
                TrayHeld := TRUE;
                IF Sim OR trayEff THEN
                    iSt := 0; Busy := FALSE; Done := TRUE;
                ELSE
                    TrayHeld := FALSE;
                    iSt := 0; Busy := FALSE; Error := TRUE;
                    ErrorID := F_Err(GVL_Cfg.SS_FORK, GVL_Cfg.ERR_SENSOR);  // tray not present
                END_IF
            ELSE
                TrayHeld := FALSE;
                iSt := 0; Busy := FALSE; Done := TRUE;
            END_IF
        END_IF
        IF AxT.Error THEN iSt := 90; END_IF
    90:
        AxZ.MoveExec := FALSE; AxT.MoveExec := FALSE;
        IF ErrorID = 0 THEN
            IF AxZ.Error THEN ErrorID := AxZ.ErrorID;
            ELSIF AxT.Error THEN ErrorID := AxT.ErrorID;
            ELSE ErrorID := F_Err(GVL_Cfg.SS_FORK, GVL_Cfg.ERR_DRIVE); END_IF
        END_IF
        iSt := 0; Busy := FALSE; Error := TRUE;
END_CASE
State := TO_UINT(iSt);

rtGoto(CLK := GotoExec);
IF rtGoto.Q AND NOT Permissive THEN
    Error := TRUE;
    ErrorID := F_Err(GVL_Cfg.SS_FRIDGE_CAR, GVL_Cfg.ERR_INTERLOCK);
END_IF

Pin.Cmd          := Vfd.PinCmd;
Vfd.PinExtended  := Pin.Extended;
Vfd.PinRetracted := Pin.Retracted;

Vfd.Enable   := Enable;
Vfd.Abort    := Abort;
Vfd.HomeExec := HomeExec;
Vfd.GotoExec := GotoExec AND Permissive;
Vfd.TargetStation := TargetFace * (GVL_Cfg.STATIONS / 2);
Vfd.Bidirectional := FALSE;

IF Vfd.ActStation = 0 THEN ActFace := 0;
ELSIF Vfd.ActStation = GVL_Cfg.STATIONS / 2 THEN ActFace := 1;
ELSE ActFace := -1; END_IF
Homed := Vfd.Homed;
Busy  := Vfd.Busy;
Done  := Vfd.Done;
IF Vfd.Error OR Pin.Error THEN
    Error := TRUE;
    IF Vfd.Error THEN ErrorID := Vfd.ErrorID; ELSE ErrorID := Pin.ErrorID; END_IF
END_IF

rtExec(CLK := CmdExec);

IF Abort THEN
    iSt := 0; Busy := FALSE;
    AxX.MoveExec := FALSE; AxT.MoveExec := FALSE; AxZ.MoveExec := FALSE;
    AxX.HomeExec := FALSE; AxT.HomeExec := FALSE; AxZ.HomeExec := FALSE;
    tonTO(IN := FALSE);
END_IF

Homed  := AxX.Sts.homed AND AxT.Sts.homed AND AxZ.Sts.homed;
Parked := Homed AND (iSt = 0) AND (ABS(AxX.Sts.actPos - GVL_Cfg.GX_PARK) < 2.0);

tonTO(IN := Busy, PT := GVL_Cfg.TO_MECH);
IF tonTO.Q AND Busy THEN
    iSt := 0; Busy := FALSE; Error := TRUE;
    ErrorID := F_Err(GVL_Cfg.SS_GANTRY, GVL_Cfg.ERR_TIMEOUT);
END_IF

CASE iSt OF
    0: // IDLE — accept command
        IF Enable AND rtExec.Q THEN
            cmdL := Cmd; Done := FALSE; Error := FALSE; ErrorID := 0;
            CASE cmdL.code OF
                1:  (* MCMD_HOME *)     iSt := 10; Busy := TRUE;
                10: (* MCMD_PICK *)
                    idx := TO_INT(cmdL.p1);
                    row := idx / GVL_Cfg.TRAY_COLS;  col := idx MOD GVL_Cfg.TRAY_COLS;
                    tgtX := GVL_Cfg.PICK_BASE_X + TO_LREAL(col) * GVL_Cfg.PICK_SPACING_X + GVL_Par.pickOffsetX;
                    tgtY := GVL_Cfg.PICK_BASE_Y + TO_LREAL(row) * GVL_Cfg.PICK_SPACING_Y + GVL_Par.pickOffsetY;
                    zTarget := GVL_Cfg.GZ_PICK;
                    iSt := 20; Busy := TRUE;
                11: (* MCMD_PLACE *)
                    idx := TO_INT(cmdL.p1);
                    row := idx / GVL_Cfg.PLACE_COLS; col := idx MOD GVL_Cfg.PLACE_COLS;
                    tgtX := GVL_Cfg.PLACE_BASE_X + TO_LREAL(col) * GVL_Cfg.PLACE_SPC_X + GVL_Par.placeOffsetX;
                    tgtY := GVL_Cfg.PLACE_BASE_Y + TO_LREAL(row) * GVL_Cfg.PLACE_SPC_Y + GVL_Par.placeOffsetY;
                    zTarget := GVL_Cfg.GZ_PLACE;
                    iSt := 20; Busy := TRUE;
                2:  (* MCMD_PARK *)
                    tgtX := GVL_Cfg.GX_PARK; tgtY := GVL_Cfg.ARM_LEN * 0.0;
                    iSt := 60; Busy := TRUE;
                13: (* MCMD_SANITIZE *)
                    tgtX := GVL_Cfg.GX_MAX;  tgtY := 0.0;    // wash-station pose TODO
                    iSt := 60; Busy := TRUE;
            ELSE
                Error := TRUE; ErrorID := F_Err(GVL_Cfg.SS_GANTRY, GVL_Cfg.ERR_BAD_CMD);
            END_CASE
        END_IF

    10: // HOME: Z up first, then theta safe, then X (collision-safe)
        AxZ.HomeExec := TRUE;
        IF AxZ.Sts.homed THEN AxZ.HomeExec := FALSE; iSt := 11; END_IF
    11:
        AxT.HomeExec := TRUE;
        IF AxT.Sts.homed THEN AxT.HomeExec := FALSE; iSt := 12; END_IF
    12:
        AxX.HomeExec := TRUE;
        IF AxX.Sts.homed THEN
            AxX.HomeExec := FALSE;
            iSt := 0; Busy := FALSE; Done := TRUE;
        END_IF

    20: // PICK/PLACE step 1: Z up
        AxZ.TargetPos := GVL_Cfg.GZ_UP;
        AxZ.Vel := GVL_Cfg.Z_VEL; AxZ.Acc := GVL_Cfg.Z_ACC;
        AxZ.MoveExec := TRUE;
        IF AxZ.Done THEN AxZ.MoveExec := FALSE; iSt := 21; END_IF
        IF AxZ.Error THEN iSt := 90; END_IF
    21: // step 2: IK + coordinated XY
        IK(xCart := tgtX, yCart := tgtY);
        IF NOT IK.Reachable THEN
            iSt := 0; Busy := FALSE; Error := TRUE;
            ErrorID := F_Err(GVL_Cfg.SS_GANTRY, GVL_Cfg.ERR_UNREACH);
        ELSE
            AxX.TargetPos := IK.xLin;     AxX.Vel := GVL_Cfg.G_VEL; AxX.Acc := GVL_Cfg.G_ACC;
            AxT.TargetPos := IK.thetaDeg; AxT.Vel := GVL_Cfg.T_VEL; AxT.Acc := GVL_Cfg.T_ACC;
            AxX.MoveExec := TRUE; AxT.MoveExec := TRUE;
            iSt := 22;
        END_IF
    22:
        IF AxX.Done AND AxT.Done THEN
            AxX.MoveExec := FALSE; AxT.MoveExec := FALSE; iSt := 23;
        END_IF
        IF AxX.Error OR AxT.Error THEN iSt := 90; END_IF
    23: // step 3: Z dip
        AxZ.TargetPos := zTarget; AxZ.MoveExec := TRUE;
        IF AxZ.Done THEN AxZ.MoveExec := FALSE; iSt := 24; END_IF
        IF AxZ.Error THEN iSt := 90; END_IF
    24: // step 4: arm grip/release; result checked next scan (Grip.Done may be stale this scan)
        IF cmdL.code = GVL_Cfg.MCMD_PICK THEN
            Grip.AcquireExec := TRUE;
        ELSE
            Grip.ReleaseExec := TRUE;
        END_IF
        iSt := 26;
    26: // wait gripper result
        IF Grip.Done THEN
            Grip.AcquireExec := FALSE; Grip.ReleaseExec := FALSE; iSt := 25;
        END_IF
        IF Grip.Error THEN
            Grip.AcquireExec := FALSE; Grip.ReleaseExec := FALSE;
            ErrorID := Grip.ErrorID; iSt := 90;
        END_IF
    25: // step 5: Z up -> done
        AxZ.TargetPos := GVL_Cfg.GZ_UP; AxZ.MoveExec := TRUE;
        IF AxZ.Done THEN
            AxZ.MoveExec := FALSE;
            iSt := 0; Busy := FALSE; Done := TRUE;
        END_IF
        IF AxZ.Error THEN iSt := 90; END_IF

    60: // PARK / SANITIZE: Z up then XY
        AxZ.TargetPos := GVL_Cfg.GZ_UP; AxZ.MoveExec := TRUE;
        IF AxZ.Done THEN AxZ.MoveExec := FALSE; iSt := 61; END_IF
        IF AxZ.Error THEN iSt := 90; END_IF
    61:
        IK(xCart := tgtX + GVL_Cfg.ARM_LEN, yCart := tgtY);  // park pose: arm at 0 deg
        AxX.TargetPos := tgtX;  AxX.Vel := GVL_Cfg.G_VEL; AxX.Acc := GVL_Cfg.G_ACC;
        AxT.TargetPos := 0.0;   AxT.Vel := GVL_Cfg.T_VEL; AxT.Acc := GVL_Cfg.T_ACC;
        AxX.MoveExec := TRUE; AxT.MoveExec := TRUE;
        iSt := 62;
    62:
        IF AxX.Done AND AxT.Done THEN
            AxX.MoveExec := FALSE; AxT.MoveExec := FALSE;
            iSt := 0; Busy := FALSE; Done := TRUE;
        END_IF
        IF AxX.Error OR AxT.Error THEN iSt := 90; END_IF

    90: // fault funnel
        AxX.MoveExec := FALSE; AxT.MoveExec := FALSE; AxZ.MoveExec := FALSE;
        Grip.AcquireExec := FALSE; Grip.ReleaseExec := FALSE;
        IF ErrorID = 0 THEN
            IF AxX.Error THEN ErrorID := AxX.ErrorID;
            ELSIF AxT.Error THEN ErrorID := AxT.ErrorID;
            ELSIF AxZ.Error THEN ErrorID := AxZ.ErrorID;
            ELSE ErrorID := F_Err(GVL_Cfg.SS_GANTRY, GVL_Cfg.ERR_DRIVE); END_IF
        END_IF
        iSt := 0; Busy := FALSE; Error := TRUE;
END_CASE
State := TO_UINT(iSt);

rtGoto(CLK := GotoExec);

// wire pin actuator to indexing driver
Pin.Cmd          := Vfd.PinCmd;
Vfd.PinExtended  := Pin.Extended;
Vfd.PinRetracted := Pin.Retracted;

blocked := rtGoto.Q AND NOT RotatePermissive;
IF blocked THEN
    Error := TRUE;
    ErrorID := F_Err(GVL_Cfg.SS_GRID_CAR, GVL_Cfg.ERR_INTERLOCK);
END_IF

Vfd.Enable   := Enable;
Vfd.Abort    := Abort;
Vfd.HomeExec := HomeExec;
Vfd.GotoExec := GotoExec AND RotatePermissive;
Vfd.TargetStation := TargetStation;
Vfd.Bidirectional := TRUE;                 // shortest signed path

ActStation := Vfd.ActStation;
Homed := Vfd.Homed;
Busy  := Vfd.Busy;
Done  := Vfd.Done;
IF Vfd.Error THEN
    Error := TRUE; ErrorID := Vfd.ErrorID;
ELSIF NOT blocked THEN
    Error := FALSE; ErrorID := 0;
END_IF
IF Pin.Error THEN
    Error := TRUE; ErrorID := Pin.ErrorID;
END_IF

rtA(CLK := AcquireExec);
rtR(CLK := ReleaseExec);
acqEff := (Sim AND Pneu.Extended) OR ((NOT Sim) AND iAcquired);

CASE state OF
    0:
        IF rtA.Q THEN Pneu.Cmd := TRUE;  state := 1; Busy := TRUE; Done := FALSE; tonTO(IN := FALSE); END_IF
        IF rtR.Q THEN Pneu.Cmd := FALSE; state := 2; Busy := TRUE; Done := FALSE; tonTO(IN := FALSE); END_IF
    1: // acquiring
        tonTO(IN := TRUE, PT := GVL_Cfg.TO_PNEU);
        IF Pneu.Extended AND acqEff THEN
            Holding := TRUE; state := 0; Busy := FALSE; Done := TRUE;
        ELSIF tonTO.Q THEN
            state := 0; Busy := FALSE; Error := TRUE;
            ErrorID := F_Err(GVL_Cfg.SS_GRIPPER, GVL_Cfg.ERR_TIMEOUT);
        END_IF
    2: // releasing
        tonTO(IN := TRUE, PT := GVL_Cfg.TO_PNEU);
        IF Pneu.Retracted THEN
            Holding := FALSE; state := 0; Busy := FALSE; Done := TRUE;
        ELSIF tonTO.Q THEN
            state := 0; Busy := FALSE; Error := TRUE;
            ErrorID := F_Err(GVL_Cfg.SS_GRIPPER, GVL_Cfg.ERR_TIMEOUT);
        END_IF
END_CASE

Reachable := FALSE;
IF ABS(yCart) > GVL_Cfg.ARM_LEN THEN RETURN; END_IF
rNorm := yCart / GVL_Cfg.ARM_LEN;
thetaR := ASIN(rNorm);
thetaDeg := thetaR * 180.0 / PI_;
xLin := xCart - GVL_Cfg.ARM_LEN * COS(thetaR);
Reachable := (xLin >= GVL_Cfg.GX_MIN) AND (xLin <= GVL_Cfg.GX_MAX)
         AND (thetaDeg >= GVL_Cfg.THETA_MIN) AND (thetaDeg <= GVL_Cfg.THETA_MAX);

rtExec(CLK := CmdExec);
scale := 1.0;
IF Sim THEN scale := GVL_Cfg.SIM_TIME_SCALE; END_IF

IF Abort THEN
    iSt := 0; Busy := FALSE;
    Drv.PathExec := FALSE; Drv.WriteParams := FALSE;
END_IF
IF Drv.Error AND (iSt <> 0) THEN
    iSt := 0; Busy := FALSE; Error := TRUE; ErrorID := Drv.ErrorID;
    Drv.PathExec := FALSE; Drv.WriteParams := FALSE;
END_IF

CASE iSt OF
    0: // idle
        IF Enable AND rtExec.Q THEN
            Done := FALSE; Error := FALSE; ErrorID := 0;
            IF (Cmd.code = GVL_Cfg.MCMD_PROFILE) THEN
                IF NOT IsOpen THEN
                    Error := TRUE; ErrorID := F_Err(GVL_Cfg.SS_PRESS_0 + TO_UINT(PressId), GVL_Cfg.ERR_INTERLOCK);
                ELSE
                    DwellS := 0.0; smashT := 0.0;
                    // push PR positions (recipe + per-press calibration trim)
                    // to the drive before commanding motion
                    Drv.OpenPosMm  := GVL_Cfg.PRESS_OPEN_MM;
                    Drv.SmashPosMm := Recipe.smashPosMm + GVL_Par.pressTrimMm[PressId];
                    Drv.HoldPosMm  := Recipe.holdPosMm  + GVL_Par.pressTrimMm[PressId];
                    Drv.WriteParams := TRUE;
                    iSt := 5; Busy := TRUE; IsOpen := FALSE;
                END_IF
            ELSIF (Cmd.code = GVL_Cfg.MCMD_OPEN) OR (Cmd.code = GVL_Cfg.MCMD_HOME) THEN
                Drv.PathNo := 0; Drv.PathExec := TRUE;          // OPEN
                iSt := 30; Busy := TRUE; Holding := FALSE;
            ELSE
                Error := TRUE; ErrorID := F_Err(GVL_Cfg.SS_PRESS_0 + TO_UINT(PressId), GVL_Cfg.ERR_BAD_CMD);
            END_IF
        END_IF
    5: // wait for PR table confirmed in drive, then smash
        IF Drv.ParamsValid THEN
            Drv.WriteParams := FALSE;
            Drv.PathNo := 1; Drv.PathExec := TRUE;              // SMASH
            iSt := 10;
        ELSIF Drv.ParamErr THEN
            Drv.WriteParams := FALSE;
            iSt := 0; Busy := FALSE; Error := TRUE;
            ErrorID := F_Err(GVL_Cfg.SS_PRESS_0 + TO_UINT(PressId), GVL_Cfg.ERR_DRIVE);
        END_IF
	10: // closing to smash position
        IF Drv.Done THEN
            Drv.PathExec := FALSE; iSt := 11;
        END_IF
    11: // dwell at smash force/position
        smashT := smashT + CycleMs / 1000.0 * scale;
        DwellS := DwellS + CycleMs / 1000.0 * scale;
        IF smashT >= Recipe.smashDurS THEN
            Drv.PathNo := 2; Drv.PathExec := TRUE;              // BACK OFF -> HOLD
            iSt := 12;
        END_IF
    12:
        IF Drv.Done THEN
            Drv.PathExec := FALSE;
            iSt := 20; Busy := FALSE; Done := TRUE; Holding := TRUE;
        END_IF
    20: // HOLDING for cook duration (open on command)
        DwellS := DwellS + CycleMs / 1000.0 * scale;
        IF Enable AND rtExec.Q AND (Cmd.code = GVL_Cfg.MCMD_OPEN) THEN
            Done := FALSE;
            Drv.PathNo := 0; Drv.PathExec := TRUE;
            iSt := 30; Busy := TRUE; Holding := FALSE;
        END_IF
    30: // opening
        IF Drv.Done THEN
            Drv.PathExec := FALSE;
            iSt := 0; Busy := FALSE; Done := TRUE; IsOpen := TRUE;
        END_IF
END_CASE
State := TO_UINT(iSt);

IF Sim THEN
    IF qCompressor THEN
        simC := simC - 0.15 * (CycleMs / 1000.0) * GVL_Cfg.SIM_TIME_SCALE;
    ELSE
        simC := simC + 0.03 * (CycleMs / 1000.0) * GVL_Cfg.SIM_TIME_SCALE;
    END_IF
    simC := LIMIT(1.0, simC, 30.0);
    ActC := simC;
ELSE
    ActC := TO_LREAL(iTempRaw) / 10.0;
END_IF

// hysteresis with min run/stop (compressor protection)
IF ActC > GVL_Cfg.FRIDGE_SET_C + GVL_Cfg.FRIDGE_HYST_C THEN compReq := TRUE; END_IF
IF ActC < GVL_Cfg.FRIDGE_SET_C - GVL_Cfg.FRIDGE_HYST_C THEN compReq := FALSE; END_IF
minRun(IN := qCompressor, PT := T#60S);
minOff(IN := NOT qCompressor, PT := T#60S);
IF Enable THEN
    IF compReq AND (minOff.Q OR Sim) THEN qCompressor := TRUE; END_IF
    IF (NOT compReq) AND (minRun.Q OR Sim) THEN qCompressor := FALSE; END_IF
ELSE
    qCompressor := FALSE;
END_IF

AtSet := ActC <= GVL_Cfg.FRIDGE_SET_C + 1.0;

IF Enable AND (ActC > GVL_Cfg.FRIDGE_SET_C + 0.5) AND AtSet = FALSE AND (GVL_Sts.mode = E_MachMode.RUN) THEN
    excT := excT + CycleMs / 1000.0 * GVL_Cfg.SIM_TIME_SCALE;
ELSE
    excT := 0.0;
END_IF
Excursion := excT >= GVL_Cfg.FRIDGE_EXC_S;
IF Excursion THEN
    ErrorID := F_Err(GVL_Cfg.SS_REFRIG, GVL_Cfg.ERR_SENSOR);
END_IF

rtExec(CLK := CmdExec);
IF Abort THEN
    iSt := 0; Busy := FALSE;
    AxX.MoveExec := FALSE; AxY.MoveExec := FALSE; AxZ.MoveExec := FALSE;
    AxX.HomeExec := FALSE; AxY.HomeExec := FALSE; AxZ.HomeExec := FALSE;
END_IF
Homed  := AxX.Sts.homed AND AxY.Sts.homed AND AxZ.Sts.homed;
Parked := Homed AND (iSt = 0);

tonTO(IN := Busy, PT := GVL_Cfg.TO_MECH);
IF tonTO.Q AND Busy THEN
    iSt := 0; Busy := FALSE; Error := TRUE;
    ErrorID := F_Err(GVL_Cfg.SS_SCRAPER, GVL_Cfg.ERR_TIMEOUT);
END_IF

CASE iSt OF
    0:
        IF Enable AND rtExec.Q THEN
            Done := FALSE; Error := FALSE; ErrorID := 0;
            CASE Cmd.code OF
                1:  (* MCMD_HOME *)  iSt := 10; Busy := TRUE;
                30: (* MCMD_SWEEP *)
                    stroke := TO_INT(Cmd.p1);
                    IF (stroke < 0) OR (stroke >= GVL_Cfg.SC_STROKES) THEN
                        Error := TRUE; ErrorID := F_Err(GVL_Cfg.SS_SCRAPER, GVL_Cfg.ERR_BAD_CMD);
                    ELSIF NOT InterlockOk THEN
                        Error := TRUE; ErrorID := F_Err(GVL_Cfg.SS_SCRAPER, GVL_Cfg.ERR_INTERLOCK);
                    ELSE
                        iSt := 20; Busy := TRUE;
                    END_IF
                2:  (* MCMD_PARK *)  iSt := 60; Busy := TRUE;
            ELSE
                Error := TRUE; ErrorID := F_Err(GVL_Cfg.SS_SCRAPER, GVL_Cfg.ERR_BAD_CMD);
            END_CASE
        END_IF
    10: // HOME: Z first
        AxZ.HomeExec := TRUE;
        IF AxZ.Sts.homed THEN AxZ.HomeExec := FALSE; iSt := 11; END_IF
    11:
        AxX.HomeExec := TRUE;
        IF AxX.Sts.homed THEN AxX.HomeExec := FALSE; iSt := 12; END_IF
    12:
        AxY.HomeExec := TRUE;
        IF AxY.Sts.homed THEN
            AxY.HomeExec := FALSE; iSt := 0; Busy := FALSE; Done := TRUE;
        END_IF
    20: // position at stroke start, Z up
        AxZ.TargetPos := GVL_Cfg.SC_UP_Z; AxZ.Vel := GVL_Cfg.Z_VEL; AxZ.Acc := GVL_Cfg.Z_ACC;
        AxZ.MoveExec := TRUE;
        IF AxZ.Done THEN AxZ.MoveExec := FALSE; iSt := 21; END_IF
        IF AxZ.Error THEN iSt := 90; END_IF
    21:
        AxX.TargetPos := GVL_Cfg.SC_SWEEP_X0; AxX.Vel := GVL_Cfg.S_VEL; AxX.Acc := GVL_Cfg.S_ACC;
        AxY.TargetPos := GVL_Cfg.SC_ROW_Y[stroke]; AxY.Vel := GVL_Cfg.S_VEL; AxY.Acc := GVL_Cfg.S_ACC;
        AxX.MoveExec := TRUE; AxY.MoveExec := TRUE;
        iSt := 22;
    22:
        IF AxX.Done AND AxY.Done THEN
            AxX.MoveExec := FALSE; AxY.MoveExec := FALSE; iSt := 23;
        END_IF
        IF AxX.Error OR AxY.Error THEN iSt := 90; END_IF
    23: // engage blade
        AxZ.TargetPos := GVL_Cfg.SC_ENGAGE_Z; AxZ.MoveExec := TRUE;
        IF AxZ.Done THEN AxZ.MoveExec := FALSE; iSt := 24; END_IF
        IF AxZ.Error THEN iSt := 90; END_IF
    24: // sweep across
        AxX.TargetPos := GVL_Cfg.SC_SWEEP_X1; AxX.MoveExec := TRUE;
        IF AxX.Done THEN AxX.MoveExec := FALSE; iSt := 25; END_IF
        IF AxX.Error THEN iSt := 90; END_IF
    25: // blade up -> done
        AxZ.TargetPos := GVL_Cfg.SC_UP_Z; AxZ.MoveExec := TRUE;
        IF AxZ.Done THEN
            AxZ.MoveExec := FALSE; iSt := 0; Busy := FALSE; Done := TRUE;
        END_IF
        IF AxZ.Error THEN iSt := 90; END_IF
    60: // PARK
        AxZ.TargetPos := GVL_Cfg.SC_UP_Z; AxZ.MoveExec := TRUE;
        IF AxZ.Done THEN AxZ.MoveExec := FALSE; iSt := 61; END_IF
        IF AxZ.Error THEN iSt := 90; END_IF
    61:
        AxX.TargetPos := 0.0; AxY.TargetPos := 0.0;
        AxX.MoveExec := TRUE; AxY.MoveExec := TRUE;
        IF AxX.Done AND AxY.Done THEN
            AxX.MoveExec := FALSE; AxY.MoveExec := FALSE;
            iSt := 0; Busy := FALSE; Done := TRUE;
        END_IF
        IF AxX.Error OR AxY.Error THEN iSt := 90; END_IF
    90:
        AxX.MoveExec := FALSE; AxY.MoveExec := FALSE; AxZ.MoveExec := FALSE;
        IF ErrorID = 0 THEN
            IF AxX.Error THEN ErrorID := AxX.ErrorID;
            ELSIF AxY.Error THEN ErrorID := AxY.ErrorID;
            ELSIF AxZ.Error THEN ErrorID := AxZ.ErrorID;
            ELSE ErrorID := F_Err(GVL_Cfg.SS_SCRAPER, GVL_Cfg.ERR_DRIVE); END_IF
        END_IF
        iSt := 0; Busy := FALSE; Error := TRUE;
END_CASE
State := TO_UINT(iSt);

dtS := CycleMs / 1000.0;
IF Sim THEN dtS := dtS * GVL_Cfg.SIM_TIME_SCALE; END_IF
rtL(CLK := SetLoading);  rtS(CLK := StartCook);  rtP(CLK := ScrapeStart);
rtD(CLK := ScrapeDone);  rtF(CLK := SetFault);
// NewHaccp stays latched until the consumer acks it (T_Comms is 5x
// slower than T_App; a 1-cycle pulse would get lost)
IF HaccpAck THEN NewHaccp := FALSE; END_IF

IF rtL.Q AND (GIdxA >= 0) AND (GIdxA <= 3) THEN
    aG[GIdxA].state := TO_UINT(E_GriddleState.LOADING);
END_IF
IF rtS.Q AND (GIdxB >= 0) AND (GIdxB <= 3) THEN
    aG[GIdxB].state := TO_UINT(E_GriddleState.COOKING);
    aG[GIdxB].item  := ItemB;
    aG[GIdxB].count := CountB;
    aG[GIdxB].batchId := BatchB;
    aG[GIdxB].cookElapsedS := 0.0;
    startS[GIdxB] := GVL_Sts.uptimeS;
END_IF
IF rtP.Q AND (GIdxC >= 0) AND (GIdxC <= 3) THEN
    aG[GIdxC].state := TO_UINT(E_GriddleState.SCRAPING);
END_IF
IF rtD.Q AND (GIdxD >= 0) AND (GIdxD <= 3) THEN
    // emit HACCP record, then empty the griddle
    rec.batchId    := aG[GIdxD].batchId;
    rec.item       := aG[GIdxD].item;
    rec.griddleId  := GIdxD;
    rec.platenTopC := GVL_Sts.aHeat[2 * GIdxD].actC;
    rec.platenBotC := GVL_Sts.aHeat[2 * GIdxD + 1].actC;
    rec.cookS      := aG[GIdxD].cookElapsedS;
    rec.tStartS    := startS[GIdxD];
    rec.tEndS      := GVL_Sts.uptimeS;
    IF (rec.platenTopC < GVL_Par.aRecipe[rec.item].platenSetC - 15.0)
       OR (rec.cookS < GVL_Par.aRecipe[rec.item].cookTimeS - 2.0) THEN
        rec.result := 1;    // QUARANTINE
    ELSE
        rec.result := 0;
    END_IF
    HaccpRec := rec; NewHaccp := TRUE;
    aG[GIdxD].state := TO_UINT(E_GriddleState.EMPTY);
    aG[GIdxD].item := 0; aG[GIdxD].count := 0; aG[GIdxD].cookElapsedS := 0.0;
END_IF
IF rtF.Q AND (GIdxE >= 0) AND (GIdxE <= 3) THEN
    aG[GIdxE].state := TO_UINT(E_GriddleState.FAULTED);
END_IF

// cook timers + due flag
ScrapeDue := FALSE; ScrapeDueG := -1;
FOR g := 0 TO 3 DO
    IF aG[g].state = TO_UINT(E_GriddleState.COOKING) THEN
        aG[g].cookElapsedS := aG[g].cookElapsedS + dtS;
        IF aG[g].cookElapsedS >= GVL_Par.aRecipe[aG[g].item].cookTimeS - GVL_Cfg.SCRAPE_GUARD_S THEN
            aG[g].state := TO_UINT(E_GriddleState.READY_TO_SCRAPE);
        END_IF
    END_IF
    IF (aG[g].state = TO_UINT(E_GriddleState.READY_TO_SCRAPE)) AND (ScrapeDueG < 0) THEN
        ScrapeDue := TRUE; ScrapeDueG := g;
    END_IF
    // keep elapsed counting until scraped (for HACCP truth)
    IF aG[g].state = TO_UINT(E_GriddleState.READY_TO_SCRAPE)
       OR aG[g].state = TO_UINT(E_GriddleState.SCRAPING) THEN
        aG[g].cookElapsedS := aG[g].cookElapsedS + dtS;
    END_IF
END_FOR

rtExec(CLK := Exec);
IF Abort THEN iSt := 0; Busy := FALSE; END_IF
tonTO(IN := Busy, PT := T#120S);
IF tonTO.Q AND Busy THEN
    iSt := 0; Busy := FALSE; Error := TRUE;
    ErrorID := F_Err(GVL_Cfg.SS_HOMING, GVL_Cfg.ERR_TIMEOUT);
END_IF

CASE iSt OF
    0:
        IF rtExec.Q THEN
            Done := FALSE; Error := FALSE; ErrorID := 0;
            iSt := 10; Busy := TRUE;
        END_IF
    10: // command all presses OPEN
        FOR i := 0 TO 3 DO
            Presses[i].Cmd.code := GVL_Cfg.MCMD_OPEN;
            Presses[i].CmdExec := TRUE;
        END_FOR
        iSt := 11;
    11:
        allOpen := TRUE;
        FOR i := 0 TO 3 DO
            IF NOT Presses[i].IsOpen THEN allOpen := FALSE; END_IF
            IF Presses[i].Error THEN iSt := 90; ErrorID := Presses[i].ErrorID; END_IF
        END_FOR
        IF allOpen AND (iSt = 11) THEN
            FOR i := 0 TO 3 DO Presses[i].CmdExec := FALSE; END_FOR
            iSt := 20;
        END_IF
    20: // gantry
        Gantry.Cmd.code := GVL_Cfg.MCMD_HOME; Gantry.CmdExec := TRUE;
        iSt := 21;
    21:
        IF Gantry.Done AND Gantry.Homed THEN Gantry.CmdExec := FALSE; iSt := 30; END_IF
        IF Gantry.Error THEN ErrorID := Gantry.ErrorID; iSt := 90; END_IF
    30: // scraper
        Scraper.Cmd.code := GVL_Cfg.MCMD_HOME; Scraper.CmdExec := TRUE;
        iSt := 31;
    31:
        IF Scraper.Done AND Scraper.Homed THEN Scraper.CmdExec := FALSE; iSt := 40; END_IF
        IF Scraper.Error THEN ErrorID := Scraper.ErrorID; iSt := 90; END_IF
    40: // fork
        Fork.Cmd.code := GVL_Cfg.MCMD_HOME; Fork.CmdExec := TRUE;
        iSt := 41;
    41:
        IF Fork.Done AND Fork.Homed THEN Fork.CmdExec := FALSE; iSt := 50; END_IF
        IF Fork.Error THEN ErrorID := Fork.ErrorID; iSt := 90; END_IF
    50: // griddle carousel
        GridCar.HomeExec := TRUE;
        iSt := 51;
    51:
        IF GridCar.Homed THEN GridCar.HomeExec := FALSE; iSt := 60; END_IF
        IF GridCar.Error THEN ErrorID := GridCar.ErrorID; iSt := 90; END_IF
    60: // fridge carousel
        FridgeCar.HomeExec := TRUE;
        iSt := 61;
    61:
        IF FridgeCar.Homed THEN
            FridgeCar.HomeExec := FALSE;
            iSt := 0; Busy := FALSE; Done := TRUE;
        END_IF
        IF FridgeCar.Error THEN ErrorID := FridgeCar.ErrorID; iSt := 90; END_IF
    90:
        Gantry.CmdExec := FALSE; Scraper.CmdExec := FALSE; Fork.CmdExec := FALSE;
        GridCar.HomeExec := FALSE; FridgeCar.HomeExec := FALSE;
        FOR i := 0 TO 3 DO Presses[i].CmdExec := FALSE; END_FOR
        iSt := 0; Busy := FALSE; Error := TRUE;
END_CASE
Step := TO_UINT(iSt);

rtPush(CLK := PushExec);
rtPop(CLK := PopExec);
rtClr(CLK := ClearExec);
IF rtClr.Q THEN head := 0; tail := 0; Count := 0; END_IF
Full  := Count >= 64;
Empty := Count = 0;
PopOk := FALSE;
IF rtPush.Q AND NOT Full THEN
    buf[head] := JobIn;
    head := (head + 1) MOD 64;
    Count := Count + 1;
END_IF
IF rtPop.Q AND NOT Empty THEN
    JobOut := buf[tail];
    tail := (tail + 1) MOD 64;
    Count := Count - 1;
    PopOk := TRUE;
END_IF

// ---- Gateway liveness ----
tonGw(IN := TRUE, PT := T#10S);   // re-armed by comms on heartbeat change
IF GVL_Cmd.gwAlive THEN tonGw(IN := FALSE); tonGw(IN := TRUE); END_IF
GVL_Sts.gwSilent := NOT GVL_Cmd.gwAlive;

// ---- rotation permissive for the griddle carousel ----
rotPerm := TRUE;
FOR i := 0 TO 3 DO
    // presses may rotate while HOLDING (they travel with the disc) but
    // never mid-motion
    IF GVL_Mech.fbPress[i].Busy THEN rotPerm := FALSE; END_IF
END_FOR
IF NOT GVL_Mech.fbGantry.Parked  THEN rotPerm := FALSE; END_IF
IF NOT GVL_Mech.fbScraper.Parked THEN rotPerm := FALSE; END_IF
GVL_Mech.fbGridCar.RotatePermissive := rotPerm;

// ---- tracker body (always runs) ----
GVL_Mech.fbTracker(Sim := GVL_Cfg.SIM_MODE);
GVL_Sts.aGriddle := GVL_Mech.fbTracker.aG;

// clear tracker command pulses after body call
GVL_Mech.fbTracker.SetLoading  := FALSE;
GVL_Mech.fbTracker.StartCook   := FALSE;
GVL_Mech.fbTracker.ScrapeStart := FALSE;
GVL_Mech.fbTracker.ScrapeDone  := FALSE;

IF GVL_Cmd.testMode THEN RETURN; END_IF
IF GVL_Sts.mode <> E_MachMode.RUN THEN
    IF iSt <> 0 THEN iSt := 0; END_IF   // mode fell out mid-primitive: mechanisms abort via Supervisor
    RETURN;
END_IF

tonStep(IN := iSt <> 0, PT := T#300S);
IF tonStep.Q AND (iSt <> 0) THEN
    GVL_Cmd.gwAck.error := TRUE;
    GVL_Cmd.gwAck.errorId := F_Err(GVL_Cfg.SS_JOBEXEC, GVL_Cfg.ERR_TIMEOUT);
    GVL_Cmd.gwAck.busy := FALSE; GVL_Cmd.gwPending := FALSE;
    iSt := 0;
END_IF

CASE iSt OF
    0: // ---- dispatch ----
        autoScrape := FALSE;
        IF GVL_Cmd.gwPending THEN
            IF GVL_Cmd.gwCmd.code = GVL_Cfg.CMD_FETCH_TRAY THEN
                item := TO_UINT(GVL_Cmd.gwCmd.p1); level := TO_INT(GVL_Cmd.gwCmd.p2); face := TO_INT(GVL_Cmd.gwCmd.p3);
                iSt := 100;
            ELSIF GVL_Cmd.gwCmd.code = GVL_Cfg.CMD_LOAD_GRIDDLE THEN
                g := TO_INT(GVL_Cmd.gwCmd.p1); count := TO_INT(GVL_Cmd.gwCmd.p2); item := TO_UINT(GVL_Cmd.gwCmd.p3);
                IF (g < 0) OR (g > 3) OR (count < 1) OR (count > GVL_Cfg.PATTIES_PER_GRIDDLE)
                   OR (GVL_Sts.aGriddle[g].state <> TO_UINT(E_GriddleState.EMPTY))
                   OR (NOT GVL_Sts.tray.inChamber) OR (GVL_Sts.tray.remaining < count) THEN
                    GVL_Cmd.gwAck.error := TRUE;
                    GVL_Cmd.gwAck.errorId := F_Err(GVL_Cfg.SS_JOBEXEC, GVL_Cfg.ERR_BAD_CMD);
                    GVL_Cmd.gwAck.busy := FALSE; GVL_Cmd.gwPending := FALSE;
                ELSE
                    iSt := 200;
                END_IF
            ELSIF GVL_Cmd.gwCmd.code = GVL_Cfg.CMD_SCRAPE THEN
                g := TO_INT(GVL_Cmd.gwCmd.p1);
                iSt := 300;
            ELSIF GVL_Cmd.gwCmd.code = GVL_Cfg.CMD_RETURN_TRAY THEN
                level := TO_INT(GVL_Cmd.gwCmd.p1); face := TO_INT(GVL_Cmd.gwCmd.p2);
                iSt := 400;
            ELSIF GVL_Cmd.gwCmd.code = GVL_Cfg.CMD_CLEAN_MODE THEN
                GVL_Cmd.reqClean := TRUE;
                GVL_Cmd.gwAck.done := TRUE; GVL_Cmd.gwAck.busy := FALSE; GVL_Cmd.gwPending := FALSE;
            ELSIF GVL_Cmd.gwCmd.code = GVL_Cfg.CMD_ABORT THEN
                GVL_Cmd.reqStop := TRUE;
                GVL_Cmd.gwAck.done := TRUE; GVL_Cmd.gwAck.busy := FALSE; GVL_Cmd.gwPending := FALSE;
            ELSE
                GVL_Cmd.gwAck.error := TRUE;
                GVL_Cmd.gwAck.errorId := F_Err(GVL_Cfg.SS_JOBEXEC, GVL_Cfg.ERR_BAD_CMD);
                GVL_Cmd.gwAck.busy := FALSE; GVL_Cmd.gwPending := FALSE;
            END_IF
        ELSIF GVL_Mech.fbTracker.ScrapeDue AND GVL_Sts.gwSilent THEN
            // AUTONOMOUS FINISH: gateway dead, cook done -> scrape locally
            g := GVL_Mech.fbTracker.ScrapeDueG;
            autoScrape := TRUE;
            iSt := 300;
        END_IF

    // ================= FETCH_TRAY =================
    100: // rotate fridge column to face (fork must be retracted/parked)
        GVL_Mech.fbFridgeCar.Permissive := NOT GVL_Mech.fbFork.Busy;
        GVL_Mech.fbFridgeCar.TargetFace := face;
        GVL_Mech.fbFridgeCar.GotoExec := TRUE;
        iSt := 101;
    101:
        IF GVL_Mech.fbFridgeCar.Done OR (GVL_Mech.fbFridgeCar.ActFace = face) THEN
            GVL_Mech.fbFridgeCar.GotoExec := FALSE; iSt := 102;
        ELSIF GVL_Mech.fbFridgeCar.Error THEN iSt := 900;
        END_IF
    102: // open fridge-side gate
        GVL_Mech.fbAirlock.ReqFridgeOpen := TRUE;
        IF GVL_Mech.fbAirlock.FridgeOpen THEN iSt := 103; END_IF
        IF GVL_Mech.fbAirlock.Error THEN iSt := 900; END_IF
    103: // fork fetch
        GVL_Mech.fbFork.Cmd.code := GVL_Cfg.MCMD_FETCH;
        GVL_Mech.fbFork.Cmd.p1 := TO_LREAL(level);
        GVL_Mech.fbFork.CmdExec := TRUE;
        iSt := 104;
    104:
        IF GVL_Mech.fbFork.Done AND GVL_Mech.fbFork.TrayHeld THEN
            GVL_Mech.fbFork.CmdExec := FALSE; iSt := 105;
        ELSIF GVL_Mech.fbFork.Error THEN
            GVL_Mech.fbFork.CmdExec := FALSE; iSt := 900;
        END_IF
    105: // close gate; publish tray info
        GVL_Mech.fbAirlock.ReqFridgeOpen := FALSE;
        IF GVL_Mech.fbAirlock.ChamberSealed THEN
            GVL_Sts.tray.item := item;
            GVL_Sts.tray.remaining := GVL_Cfg.PATTIES_PER_TRAY;
            GVL_Sts.tray.level := level; GVL_Sts.tray.face := face;
            GVL_Sts.tray.inChamber := TRUE;
            iSt := 990;
        END_IF

    // ================= LOAD_GRIDDLE =================
    200: // bring griddle g to load station
        GVL_Mech.fbTracker.SetLoading := TRUE; GVL_Mech.fbTracker.GIdxA := g;
        GVL_Mech.fbGridCar.TargetStation := g;
        GVL_Mech.fbGridCar.GotoExec := TRUE;
        iSt := 201;
    201:
        IF GVL_Mech.fbGridCar.Done OR (GVL_Mech.fbGridCar.ActStation = g) THEN
            GVL_Mech.fbGridCar.GotoExec := FALSE; iSt := 202;
        ELSIF GVL_Mech.fbGridCar.Error THEN iSt := 900;
        END_IF
    202: // open chamber gate (fridge side must be sealed)
        GVL_Mech.fbAirlock.ReqChamberOpen := TRUE;
        IF GVL_Mech.fbAirlock.ChamberOpen THEN i := 0; iSt := 210; END_IF
        IF GVL_Mech.fbAirlock.Error THEN iSt := 900; END_IF
    210: // pick patty i from tray
        trayIdx := GVL_Cfg.PATTIES_PER_TRAY - GVL_Sts.tray.remaining;
        GVL_Mech.fbGantry.Cmd.code := GVL_Cfg.MCMD_PICK;
        GVL_Mech.fbGantry.Cmd.p1 := TO_LREAL(trayIdx);
        GVL_Mech.fbGantry.CmdExec := TRUE;
        iSt := 211;
    211:
        IF GVL_Mech.fbGantry.Done THEN
            GVL_Mech.fbGantry.CmdExec := FALSE; iSt := 212;
        ELSIF GVL_Mech.fbGantry.Error THEN
            GVL_Mech.fbGantry.CmdExec := FALSE; iSt := 900;
        END_IF
    212: // place on griddle slot i
        GVL_Mech.fbGantry.Cmd.code := GVL_Cfg.MCMD_PLACE;
        GVL_Mech.fbGantry.Cmd.p1 := TO_LREAL(i);
        GVL_Mech.fbGantry.CmdExec := TRUE;
        iSt := 213;
    213:
        IF GVL_Mech.fbGantry.Done THEN
            GVL_Mech.fbGantry.CmdExec := FALSE;
            GVL_Sts.pattyOnGriddle[g, i] := TRUE;
            GVL_Sts.tray.remaining := GVL_Sts.tray.remaining - 1;
            i := i + 1;
            IF i >= count THEN iSt := 220; ELSE iSt := 210; END_IF
        ELSIF GVL_Mech.fbGantry.Error THEN
            GVL_Mech.fbGantry.CmdExec := FALSE; iSt := 900;
        END_IF
    220: // park gantry, close chamber
        GVL_Mech.fbGantry.Cmd.code := GVL_Cfg.MCMD_PARK;
        GVL_Mech.fbGantry.CmdExec := TRUE;
        iSt := 221;
    221:
        IF GVL_Mech.fbGantry.Done THEN
            GVL_Mech.fbGantry.CmdExec := FALSE;
            GVL_Mech.fbAirlock.ReqChamberOpen := FALSE;
            iSt := 222;
        ELSIF GVL_Mech.fbGantry.Error THEN
            GVL_Mech.fbGantry.CmdExec := FALSE; iSt := 900;
        END_IF
    222:
        IF GVL_Mech.fbAirlock.ChamberSealed THEN iSt := 230; END_IF
    230: // run press profile + start cook clock
        GVL_Mech.fbPress[g].Recipe := GVL_Par.aRecipe[item];
        GVL_Mech.fbPress[g].Cmd.code := GVL_Cfg.MCMD_PROFILE;
        GVL_Mech.fbPress[g].CmdExec := TRUE;
        iSt := 231;
    231:
        IF GVL_Mech.fbPress[g].Holding THEN
            GVL_Mech.fbPress[g].CmdExec := FALSE;
            batchSeq := batchSeq + 1;
            GVL_Mech.fbTracker.StartCook := TRUE;
            GVL_Mech.fbTracker.GIdxB := g;
            GVL_Mech.fbTracker.ItemB := item;
            GVL_Mech.fbTracker.CountB := count;
            GVL_Mech.fbTracker.BatchB := batchSeq;
            iSt := 990;
        ELSIF GVL_Mech.fbPress[g].Error THEN
            GVL_Mech.fbPress[g].CmdExec := FALSE; iSt := 900;
        END_IF

    // ================= SCRAPE =================
    300: // open press g first
        GVL_Mech.fbTracker.ScrapeStart := TRUE; GVL_Mech.fbTracker.GIdxC := g;
        GVL_Mech.fbPress[g].Cmd.code := GVL_Cfg.MCMD_OPEN;
        GVL_Mech.fbPress[g].CmdExec := TRUE;
        iSt := 301;
    301:
        IF GVL_Mech.fbPress[g].IsOpen THEN
            GVL_Mech.fbPress[g].CmdExec := FALSE; iSt := 302;
        ELSIF GVL_Mech.fbPress[g].Error THEN
            GVL_Mech.fbPress[g].CmdExec := FALSE; iSt := 900;
        END_IF
    302: // rotate griddle g to scrape station
        GVL_Mech.fbGridCar.TargetStation := (g + 2) MOD 4;
        GVL_Mech.fbGridCar.GotoExec := TRUE;
        iSt := 303;
    303:
        IF (GVL_Mech.fbGridCar.Done OR (GVL_Mech.fbGridCar.ActStation = (g + 2) MOD 4))
           AND NOT GVL_Mech.fbGridCar.Busy THEN   // arrival can be reported while still settling
            GVL_Mech.fbGridCar.GotoExec := FALSE;
            scrapeStroke := 0; iSt := 310;
        ELSIF GVL_Mech.fbGridCar.Error THEN iSt := 900;
        END_IF
    310: // sweep strokes — only command when the interlock is actually satisfied
        GVL_Mech.fbScraper.InterlockOk := GVL_Mech.fbPress[g].IsOpen AND NOT GVL_Mech.fbGridCar.Busy;
        IF GVL_Mech.fbScraper.InterlockOk THEN
            GVL_Mech.fbScraper.Cmd.code := GVL_Cfg.MCMD_SWEEP;
            GVL_Mech.fbScraper.Cmd.p1 := TO_LREAL(scrapeStroke);
            GVL_Mech.fbScraper.CmdExec := TRUE;
            iSt := 311;
        END_IF
    311:
        IF GVL_Mech.fbScraper.Done THEN
            GVL_Mech.fbScraper.CmdExec := FALSE;
            scrapeStroke := scrapeStroke + 1;
            IF scrapeStroke >= GVL_Cfg.SC_STROKES THEN iSt := 320; ELSE iSt := 310; END_IF
        ELSIF GVL_Mech.fbScraper.Error THEN
            GVL_Mech.fbScraper.CmdExec := FALSE; iSt := 900;
        END_IF
    320: // park scraper, finish batch bookkeeping
        GVL_Mech.fbScraper.Cmd.code := GVL_Cfg.MCMD_PARK;
        GVL_Mech.fbScraper.CmdExec := TRUE;
        iSt := 321;
    321:
        IF GVL_Mech.fbScraper.Done THEN
            GVL_Mech.fbScraper.CmdExec := FALSE;
            FOR i := 0 TO 5 DO GVL_Sts.pattyOnGriddle[g, i] := FALSE; END_FOR
            GVL_Mech.fbTracker.ScrapeDone := TRUE; GVL_Mech.fbTracker.GIdxD := g;
            iSt := 990;
        ELSIF GVL_Mech.fbScraper.Error THEN
            GVL_Mech.fbScraper.CmdExec := FALSE; iSt := 900;
        END_IF

    // ================= RETURN_TRAY =================
    400:
        GVL_Mech.fbAirlock.ReqFridgeOpen := TRUE;
        IF GVL_Mech.fbAirlock.FridgeOpen THEN iSt := 401; END_IF
        IF GVL_Mech.fbAirlock.Error THEN iSt := 900; END_IF
    401:
        GVL_Mech.fbFork.Cmd.code := GVL_Cfg.MCMD_RETURN;
        GVL_Mech.fbFork.Cmd.p1 := TO_LREAL(level);
        GVL_Mech.fbFork.CmdExec := TRUE;
        iSt := 402;
    402:
        IF GVL_Mech.fbFork.Done THEN
            GVL_Mech.fbFork.CmdExec := FALSE;
            GVL_Mech.fbAirlock.ReqFridgeOpen := FALSE;
            GVL_Sts.tray.inChamber := FALSE;
            iSt := 403;
        ELSIF GVL_Mech.fbFork.Error THEN
            GVL_Mech.fbFork.CmdExec := FALSE; iSt := 900;
        END_IF
    403:
        IF GVL_Mech.fbAirlock.ChamberSealed THEN iSt := 990; END_IF

    // ================= exits =================
    900: // primitive failed
        IF NOT autoScrape THEN
            GVL_Cmd.gwAck.error := TRUE;
            GVL_Cmd.gwAck.errorId := F_Err(GVL_Cfg.SS_JOBEXEC, GVL_Cfg.ERR_DRIVE);
            GVL_Cmd.gwAck.busy := FALSE; GVL_Cmd.gwPending := FALSE;
        END_IF
        iSt := 0;
    990: // primitive done
        IF NOT autoScrape THEN
            GVL_Cmd.gwAck.done := TRUE;
            GVL_Cmd.gwAck.busy := FALSE; GVL_Cmd.gwPending := FALSE;
        END_IF
        iSt := 0;
END_CASE

// effective safety status
GVL_Sts.safetyOk := GVL_Cfg.SIM_MODE OR GVL_IO.iSafetyOk;

rtStart(CLK := GVL_Cmd.reqStart);
rtStop (CLK := GVL_Cmd.reqStop);
rtReset(CLK := GVL_Cmd.reqReset);
rtClean(CLK := GVL_Cmd.reqClean);

// defaults each scan
GVL_Sts.resetPulse := FALSE;

// global overrides
IF NOT GVL_Sts.safetyOk THEN
    GVL_Sts.mode := E_MachMode.ESTOP;
END_IF
IF GVL_Alm.reqMachStop AND (GVL_Sts.mode <> E_MachMode.ESTOP) THEN
    GVL_Sts.mode := E_MachMode.FAULT;
END_IF

CASE GVL_Sts.mode OF
    E_MachMode.BOOT:
        GVL_Sts.enMotion := FALSE; GVL_Sts.enProcess := FALSE;
        GVL_Sts.abortAll := FALSE;
        IF GVL_Sts.safetyOk AND NOT firstScan THEN
            GVL_Sts.resetPulse := TRUE;
            GVL_Mech.fbHoming.Exec := TRUE;
            GVL_Sts.mode := E_MachMode.HOMING;
        END_IF

    E_MachMode.HOMING:
        GVL_Sts.enMotion := TRUE; GVL_Sts.enProcess := FALSE;
        IF GVL_Mech.fbHoming.Done THEN
            GVL_Mech.fbHoming.Exec := FALSE;
            GVL_Sts.mode := E_MachMode.READY;
        ELSIF GVL_Mech.fbHoming.Error THEN
            GVL_Mech.fbHoming.Exec := FALSE;
            GVL_Sts.mode := E_MachMode.FAULT;
        END_IF

    E_MachMode.READY:
        GVL_Sts.enMotion := TRUE; GVL_Sts.enProcess := TRUE;   // heat-up + pulldown
        IF GVL_Alm.reqZoneStop THEN
            GVL_Sts.mode := E_MachMode.FAULT;
        ELSIF rtStart.Q AND GVL_Sts.heatAtSet AND GVL_Sts.fridgeAtSet AND GVL_Sts.allHomed THEN
            GVL_Sts.mode := E_MachMode.RUN;
        END_IF

    E_MachMode.RUN:
        GVL_Sts.enMotion := TRUE; GVL_Sts.enProcess := TRUE;
        IF GVL_Alm.reqZoneStop THEN
            GVL_Sts.mode := E_MachMode.FAULT;
        ELSIF rtStop.Q THEN
            GVL_Sts.mode := E_MachMode.READY;      // finish-in-place is JobExec's job
        ELSIF rtClean.Q AND (GVL_Mech.fbQueue.Empty) THEN
            GVL_Sts.mode := E_MachMode.CLEAN;
        END_IF

    E_MachMode.CLEAN:
        GVL_Sts.enMotion := FALSE;                  // motion locked for operator
        GVL_Sts.enProcess := FALSE;                 // heaters off -> cool down
        coolOk := TRUE;
        FOR z := 0 TO 7 DO
            IF GVL_Sts.aHeat[z].actC >= 60.0 THEN coolOk := FALSE; END_IF
        END_FOR
        GVL_Sts.cleanCoolOk := coolOk;
        IF rtStart.Q AND coolOk THEN                // operator confirms clean done
            GVL_Sts.resetPulse := TRUE;
            GVL_Mech.fbHoming.Exec := TRUE;
            GVL_Sts.mode := E_MachMode.HOMING;
        END_IF

    E_MachMode.FAULT:
        GVL_Sts.enMotion := FALSE; GVL_Sts.enProcess := FALSE;
        GVL_Sts.abortAll := TRUE;
        IF rtReset.Q AND (NOT GVL_Alm.reqMachStop) AND (NOT GVL_Alm.reqZoneStop) THEN
            GVL_Sts.abortAll := FALSE;
            GVL_Sts.resetPulse := TRUE;
            GVL_Mech.fbHoming.Exec := TRUE;
            GVL_Sts.mode := E_MachMode.HOMING;
        END_IF

    E_MachMode.ESTOP:
        GVL_Sts.enMotion := FALSE; GVL_Sts.enProcess := FALSE;
        GVL_Sts.abortAll := TRUE;
        IF GVL_Sts.safetyOk AND rtReset.Q THEN
            GVL_Sts.abortAll := FALSE;
            GVL_Sts.resetPulse := TRUE;
            GVL_Mech.fbHoming.Exec := TRUE;
            GVL_Sts.mode := E_MachMode.HOMING;
        END_IF
END_CASE
firstScan := FALSE;

// homing manager body (same task, before PRG_Carousels)
GVL_Mech.fbHoming(
    Abort     := GVL_Sts.abortAll,
    Presses   := GVL_Mech.fbPress,
    Gantry    := GVL_Mech.fbGantry,
    Scraper   := GVL_Mech.fbScraper,
    Fork      := GVL_Mech.fbFork,
    GridCar   := GVL_Mech.fbGridCar,
    FridgeCar := GVL_Mech.fbFridgeCar);

// aggregates
GVL_Sts.allHomed := GVL_Mech.fbGantry.Homed AND GVL_Mech.fbScraper.Homed
                AND GVL_Mech.fbFork.Homed AND GVL_Mech.fbGridCar.Homed
                AND GVL_Mech.fbFridgeCar.Homed;
GVL_Sts.heatAtSet   := GVL_Mech.fbHeatBank.AllAtSet;
GVL_Sts.fridgeAtSet := GVL_Mech.fbRefrig.AtSet;
GVL_Sts.fridgeActC  := GVL_Mech.fbRefrig.ActC;

// ---- collect (edge-raised) ----
rtFrk(CLK := GVL_Mech.fbFork.Error);
IF rtFrk.Q THEN
    IF SHR(GVL_Mech.fbFork.ErrorID, 16) = TO_UDINT(GVL_Cfg.SS_FORK_Z) THEN
        F_RaiseAlarm(GVL_Mech.fbFork.ErrorID, TO_UINT(E_FaultClass.MACHINE_STOP));
    ELSE
        F_RaiseAlarm(GVL_Mech.fbFork.ErrorID, TO_UINT(E_FaultClass.ZONE_STOP));
    END_IF
END_IF
rtGan(CLK := GVL_Mech.fbGantry.Error);
IF rtGan.Q THEN F_RaiseAlarm(GVL_Mech.fbGantry.ErrorID, TO_UINT(E_FaultClass.ZONE_STOP)); END_IF
rtScr(CLK := GVL_Mech.fbScraper.Error);
IF rtScr.Q THEN F_RaiseAlarm(GVL_Mech.fbScraper.ErrorID, TO_UINT(E_FaultClass.ZONE_STOP)); END_IF
rtGC(CLK := GVL_Mech.fbGridCar.Error);
IF rtGC.Q THEN F_RaiseAlarm(GVL_Mech.fbGridCar.ErrorID, TO_UINT(E_FaultClass.ZONE_STOP)); END_IF
rtFC(CLK := GVL_Mech.fbFridgeCar.Error);
IF rtFC.Q THEN F_RaiseAlarm(GVL_Mech.fbFridgeCar.ErrorID, TO_UINT(E_FaultClass.ZONE_STOP)); END_IF
rtAir(CLK := GVL_Mech.fbAirlock.Error);
IF rtAir.Q THEN F_RaiseAlarm(GVL_Mech.fbAirlock.ErrorID, TO_UINT(E_FaultClass.ZONE_STOP)); END_IF
FOR i := 0 TO 3 DO
    rtPress[i](CLK := GVL_Mech.fbPress[i].Error);
    IF rtPress[i].Q THEN
        F_RaiseAlarm(GVL_Mech.fbPress[i].ErrorID, TO_UINT(E_FaultClass.ZONE_STOP));
    END_IF
END_FOR
FOR i := 0 TO 7 DO
    rtHeat[i](CLK := GVL_Mech.fbHeater[i].Error);
    IF rtHeat[i].Q THEN
        F_RaiseAlarm(GVL_Mech.fbHeater[i].ErrorID, TO_UINT(E_FaultClass.ZONE_STOP));
    END_IF
END_FOR
rtExc(CLK := GVL_Mech.fbRefrig.Excursion);
IF rtExc.Q THEN
    F_RaiseAlarm(GVL_Mech.fbRefrig.ErrorID, TO_UINT(E_FaultClass.QUARANTINE));
END_IF
rtGw(CLK := GVL_Sts.gwSilent AND (GVL_Sts.mode = E_MachMode.RUN) AND NOT GVL_Cmd.testMode);
IF rtGw.Q THEN
    F_RaiseAlarm(F_Err(GVL_Cfg.SS_GWCOMMS, GVL_Cfg.ERR_TIMEOUT), TO_UINT(E_FaultClass.INFO));
END_IF

// ---- ack / clear ----
rtAck(CLK := GVL_Cmd.reqAckAll);
n := 0; worst := 0;
FOR i := 0 TO 63 DO
    IF GVL_Alm.aActive[i].active THEN
        IF rtAck.Q THEN GVL_Alm.aActive[i].acked := TRUE; END_IF
        IF GVL_Alm.aActive[i].acked THEN
            GVL_Alm.aActive[i].active := FALSE;
        ELSE
            n := n + 1;
            IF GVL_Alm.aActive[i].class > worst THEN worst := GVL_Alm.aActive[i].class; END_IF
        END_IF
    END_IF
END_FOR
GVL_Alm.nActive := n;
GVL_Alm.worstClass := worst;
GVL_Alm.reqZoneStop := worst >= TO_UINT(E_FaultClass.ZONE_STOP);
GVL_Alm.reqMachStop := worst >= TO_UINT(E_FaultClass.MACHINE_STOP);
GVL_Sts.activeAlarms := n;

// ---------- decode command ----------
GVL_Cmd.gwCmd.seq  := GVL_Cmd.mbCmdRegs[0];
GVL_Cmd.gwCmd.code := GVL_Cmd.mbCmdRegs[1];
GVL_Cmd.gwCmd.p1 := WORD_TO_DINT(GVL_Cmd.mbCmdRegs[2]) + SHL(WORD_TO_DINT(GVL_Cmd.mbCmdRegs[3]), 16);
GVL_Cmd.gwCmd.p2 := WORD_TO_DINT(GVL_Cmd.mbCmdRegs[4]) + SHL(WORD_TO_DINT(GVL_Cmd.mbCmdRegs[5]), 16);
GVL_Cmd.gwCmd.p3 := WORD_TO_DINT(GVL_Cmd.mbCmdRegs[6]) + SHL(WORD_TO_DINT(GVL_Cmd.mbCmdRegs[7]), 16);
GVL_Cmd.gwCmd.p4 := WORD_TO_DINT(GVL_Cmd.mbCmdRegs[8]);
GVL_Cmd.gwHeartbeatIn := GVL_Cmd.mbCmdRegs[9];

// ---------- gateway liveness (heartbeat must CHANGE) ----------
IF GVL_Cmd.gwHeartbeatIn <> lastHb THEN
    lastHb := GVL_Cmd.gwHeartbeatIn; hbAge := 0;
ELSE
    hbAge := MIN(hbAge + 1, 32000);
END_IF
GVL_Cmd.gwAlive := hbAge < 100;   // 100 * 100 ms = 10 s

// ---------- new command latch ----------
IF (GVL_Cmd.gwCmd.seq <> lastSeq) AND (GVL_Cmd.gwCmd.seq <> 0) THEN
    IF GVL_Cmd.gwPending OR GVL_Cmd.gwAck.busy THEN
        // reject: still executing previous
        GVL_Cmd.gwAck.error := TRUE;
        GVL_Cmd.gwAck.errorId := F_Err(GVL_Cfg.SS_GWCOMMS, GVL_Cfg.ERR_BUSY);
        lastSeq := GVL_Cmd.gwCmd.seq;
        GVL_Cmd.gwAck.seqEcho := lastSeq;
    ELSIF GVL_Cmd.testMode THEN
        GVL_Cmd.gwAck.error := TRUE;
        GVL_Cmd.gwAck.errorId := F_Err(GVL_Cfg.SS_GWCOMMS, GVL_Cfg.ERR_INTERLOCK);
        lastSeq := GVL_Cmd.gwCmd.seq;
        GVL_Cmd.gwAck.seqEcho := lastSeq;
    ELSE
        lastSeq := GVL_Cmd.gwCmd.seq;
        GVL_Cmd.gwAck.seqEcho := lastSeq;
        GVL_Cmd.gwAck.busy := TRUE;
        GVL_Cmd.gwAck.done := FALSE;
        GVL_Cmd.gwAck.error := FALSE;
        GVL_Cmd.gwAck.errorId := 0;
        GVL_Cmd.gwPending := TRUE;
    END_IF
END_IF

// ---------- pack ack ----------
flags := 0;
IF GVL_Cmd.gwAck.busy  THEN flags := flags OR 16#0001; END_IF
IF GVL_Cmd.gwAck.done  THEN flags := flags OR 16#0002; END_IF
IF GVL_Cmd.gwAck.error THEN flags := flags OR 16#0004; END_IF
GVL_Cmd.mbAckRegs[0] := GVL_Cmd.gwAck.seqEcho;
GVL_Cmd.mbAckRegs[1] := flags;
GVL_Cmd.mbAckRegs[2] := DWORD_TO_WORD(GVL_Cmd.gwAck.errorId AND 16#FFFF);
GVL_Cmd.mbAckRegs[3] := DWORD_TO_WORD(SHR(GVL_Cmd.gwAck.errorId, 16));
GVL_Sts.heartbeat := GVL_Sts.heartbeat + 1;
GVL_Cmd.mbAckRegs[4] := GVL_Sts.heartbeat;

// ---------- pack status ----------
GVL_Cmd.mbStsRegs[0] := TO_WORD(TO_UINT(GVL_Sts.mode));
GVL_Cmd.mbStsRegs[1] := BOOL_TO_WORD(GVL_Sts.allHomed)
                      + SHL(BOOL_TO_WORD(GVL_Sts.heatAtSet), 1)
                      + SHL(BOOL_TO_WORD(GVL_Sts.fridgeAtSet), 2)
                      + SHL(BOOL_TO_WORD(GVL_Sts.gwSilent), 3)
                      + SHL(BOOL_TO_WORD(GVL_Cmd.testMode), 4);
FOR z := 0 TO 7 DO
    GVL_Cmd.mbStsRegs[10 + z] := TO_WORD(LREAL_TO_INT(GVL_Sts.aHeat[z].actC * 10.0));
END_FOR
GVL_Cmd.mbStsRegs[18] := TO_WORD(LREAL_TO_INT(GVL_Sts.fridgeActC * 10.0));
FOR gIdx := 0 TO 3 DO
    GVL_Cmd.mbStsRegs[20 + 3 * gIdx]     := TO_WORD(GVL_Sts.aGriddle[gIdx].state);
    GVL_Cmd.mbStsRegs[20 + 3 * gIdx + 1] := TO_WORD(GVL_Sts.aGriddle[gIdx].item);
    GVL_Cmd.mbStsRegs[20 + 3 * gIdx + 2] := TO_WORD(LREAL_TO_INT(GVL_Sts.aGriddle[gIdx].cookElapsedS));
END_FOR
GVL_Cmd.mbStsRegs[32] := TO_WORD(TO_UINT(GVL_Sts.tray.remaining));
GVL_Cmd.mbStsRegs[33] := BOOL_TO_WORD(GVL_Sts.tray.inChamber);
GVL_Cmd.mbStsRegs[34] := TO_WORD(TO_UINT(GVL_Sts.activeAlarms));
GVL_Cmd.mbStsRegs[35] := TO_WORD(TO_UINT(GVL_Sts.carGridStation + 1));
GVL_Cmd.mbStsRegs[36] := UDINT_TO_WORD(GVL_Sts.haccpCount AND 16#FFFF);
// latest HACCP record snapshot (Gateway drains richer log later — TODO ring window)
GVL_Cmd.mbStsRegs[60] := UDINT_TO_WORD(GVL_Sts.lastHaccp.batchId AND 16#FFFF);
GVL_Cmd.mbStsRegs[61] := TO_WORD(GVL_Sts.lastHaccp.item);
GVL_Cmd.mbStsRegs[62] := TO_WORD(TO_UINT(GVL_Sts.lastHaccp.griddleId));
GVL_Cmd.mbStsRegs[63] := TO_WORD(LREAL_TO_INT(GVL_Sts.lastHaccp.platenTopC * 10.0));
GVL_Cmd.mbStsRegs[64] := TO_WORD(LREAL_TO_INT(GVL_Sts.lastHaccp.platenBotC * 10.0));
GVL_Cmd.mbStsRegs[65] := TO_WORD(LREAL_TO_INT(GVL_Sts.lastHaccp.cookS));
GVL_Cmd.mbStsRegs[66] := TO_WORD(GVL_Sts.lastHaccp.result);

// ---------- recipe writes (READY only, bounds-checked) ----------
parToggle := GVL_Cmd.mbParRegs[3];
IF (parToggle <> lastParTog) AND (GVL_Sts.mode = E_MachMode.READY) THEN
    lastParTog := parToggle;
    itemP := WORD_TO_INT(GVL_Cmd.mbParRegs[0]);
    cookP := TO_LREAL(WORD_TO_INT(GVL_Cmd.mbParRegs[1])) / 10.0;
    setP  := TO_LREAL(WORD_TO_INT(GVL_Cmd.mbParRegs[2])) / 10.0;
    IF (itemP >= 1) AND (itemP <= 4)
       AND (cookP >= 20.0) AND (cookP <= 300.0)
       AND (setP >= 120.0) AND (setP <= 230.0) THEN
        GVL_Par.aRecipe[itemP].cookTimeS  := cookP;
        GVL_Par.aRecipe[itemP].platenSetC := setP;
    END_IF
END_IF

IF GVL_Mech.fbTracker.NewHaccp AND NOT GVL_Mech.fbTracker.HaccpAck THEN
    ring[head] := GVL_Mech.fbTracker.HaccpRec;
    head := (head + 1) MOD 512;
    GVL_Sts.haccpCount := GVL_Sts.haccpCount + 1;
    GVL_Sts.lastHaccp := GVL_Mech.fbTracker.HaccpRec;
    IF GVL_Mech.fbTracker.HaccpRec.result = 1 THEN
        F_RaiseAlarm(F_Err(GVL_Cfg.SS_JOBEXEC, GVL_Cfg.ERR_SENSOR),
                     TO_UINT(E_FaultClass.QUARANTINE));
    END_IF
    GVL_Mech.fbTracker.HaccpAck := TRUE;       // tracker clears NewHaccp
ELSIF NOT GVL_Mech.fbTracker.NewHaccp THEN
    GVL_Mech.fbTracker.HaccpAck := FALSE;      // handshake complete, re-arm
END_IF

// ---------- LT2100E register unpack (HMI writes %MW600..609) ----------
// reg[0] button bits: 0=start 1=stop 2=reset 3=ack 4=clean
//                     5=jog+ 6=jog- 7=recipeWrite 8=trimWrite
// Numerics are copied only while their write/jog bit is held, so direct
// variable writes (watch list / sim testing) keep working unchanged.
IF GVL_Cmd.hmiRegsCmd[1] <> 0 THEN
    GVL_Cmd.hmiMaintPin := TO_UINT(GVL_Cmd.hmiRegsCmd[1]);
END_IF
IF (GVL_Cmd.hmiRegsCmd[0] AND 16#0060) <> 0 THEN            // a jog bit is held
    GVL_Cmd.hmiJogAxis := TO_INT(GVL_Cmd.hmiRegsCmd[2]);
END_IF
IF (GVL_Cmd.hmiRegsCmd[0] AND 16#0080) <> 0 THEN            // recipe write
    GVL_Cmd.hmiRecItem  := TO_UINT(GVL_Cmd.hmiRegsCmd[3]);
    GVL_Cmd.hmiRecField := TO_UINT(GVL_Cmd.hmiRegsCmd[4]);
    GVL_Cmd.hmiRecValue := TO_LREAL(GVL_Cmd.hmiRegsCmd[5]) / 10.0;   // x10 scaling
END_IF
IF (GVL_Cmd.hmiRegsCmd[0] AND 16#0100) <> 0 THEN            // trim write
    GVL_Cmd.hmiTrimPress := TO_UINT(GVL_Cmd.hmiRegsCmd[6]);
    GVL_Cmd.hmiTrimDelta := TO_LREAL(TO_INT(GVL_Cmd.hmiRegsCmd[7])) / 100.0;  // x100 signed
END_IF
bJogP := GVL_Cmd.hmiJogPlus  OR ((GVL_Cmd.hmiRegsCmd[0] AND 16#0020) <> 0);
bJogM := GVL_Cmd.hmiJogMinus OR ((GVL_Cmd.hmiRegsCmd[0] AND 16#0040) <> 0);

rtStart(CLK := GVL_Cmd.hmiStart OR ((GVL_Cmd.hmiRegsCmd[0] AND 16#0001) <> 0));
rtStop (CLK := GVL_Cmd.hmiStop  OR ((GVL_Cmd.hmiRegsCmd[0] AND 16#0002) <> 0));
rtReset(CLK := GVL_Cmd.hmiReset OR ((GVL_Cmd.hmiRegsCmd[0] AND 16#0004) <> 0));
rtAck  (CLK := GVL_Cmd.hmiAck   OR ((GVL_Cmd.hmiRegsCmd[0] AND 16#0008) <> 0));
rtClean(CLK := GVL_Cmd.hmiClean OR ((GVL_Cmd.hmiRegsCmd[0] AND 16#0010) <> 0));

GVL_Cmd.reqStart  := rtStart.Q;
GVL_Cmd.reqStop   := rtStop.Q  OR GVL_Cmd.reqStop;    // JobExec may also set; consumed by Supervisor edge
GVL_Cmd.reqReset  := rtReset.Q;
GVL_Cmd.reqAckAll := rtAck.Q;
GVL_Cmd.reqClean  := rtClean.Q OR GVL_Cmd.reqClean;
// self-clearing one-shot semantics: Supervisor uses R_TRIG on these,
// so clear them after one comms cycle
IF NOT rtStop.Q  THEN GVL_Cmd.reqStop  := FALSE; END_IF
IF NOT rtClean.Q THEN GVL_Cmd.reqClean := FALSE; END_IF

// ---------- jog (maintenance only) ----------
jogPermit := (GVL_Cmd.hmiMaintPin = MAINT_PIN)
         AND ((GVL_Sts.mode = E_MachMode.READY) OR (GVL_Sts.mode = E_MachMode.FAULT))
         AND GVL_Sts.safetyOk;
tonJog(IN := jogPermit AND (bJogP OR bJogM), PT := T#100MS);
IF tonJog.Q THEN
    tonJog(IN := FALSE);
    jogStep := LIMIT(1.0, GVL_Par.jogVel, GVL_Cfg.JOG_VEL_MAX) * 0.1;  // mm per 100 ms
    IF bJogM THEN jogStep := -jogStep; END_IF
    CASE GVL_Cmd.hmiJogAxis OF
        1: IF NOT GVL_Mech.axGX.Busy THEN
               GVL_Mech.axGX.TargetPos := GVL_Mech.axGX.Sts.actPos + jogStep;
               GVL_Mech.axGX.Vel := GVL_Par.jogVel;
               GVL_Mech.axGX.MoveExec := TRUE;
           END_IF
        2: IF NOT GVL_Mech.axGT.Busy THEN
               GVL_Mech.axGT.TargetPos := GVL_Mech.axGT.Sts.actPos + jogStep;
               GVL_Mech.axGT.Vel := GVL_Par.jogVel;
               GVL_Mech.axGT.MoveExec := TRUE;
           END_IF
        3: IF NOT GVL_Mech.axGZ.Busy THEN
               GVL_Mech.axGZ.TargetPos := GVL_Mech.axGZ.Sts.actPos + jogStep;
               GVL_Mech.axGZ.Vel := GVL_Par.jogVel;
               GVL_Mech.axGZ.MoveExec := TRUE;
           END_IF
        // axes 4..8: same pattern for scraper X/Y/Z, fork Z/tele — add as needed
    END_CASE
ELSIF NOT (bJogP OR bJogM) THEN
    GVL_Mech.axGX.MoveExec := FALSE;
    GVL_Mech.axGT.MoveExec := FALSE;
    GVL_Mech.axGZ.MoveExec := FALSE;
END_IF

// ---------- recipe editor (bounds-checked; rejected while RUN) ----------
rtRecW(CLK := GVL_Cmd.hmiRecWrite OR ((GVL_Cmd.hmiRegsCmd[0] AND 16#0080) <> 0));
IF rtRecW.Q THEN
    GVL_Cmd.hmiRecAck := FALSE; GVL_Cmd.hmiRecErr := FALSE;
    recIt := TO_INT(GVL_Cmd.hmiRecItem);
    recV  := GVL_Cmd.hmiRecValue;
    recOk := (recIt >= 1) AND (recIt <= 4) AND (GVL_Sts.mode <> E_MachMode.RUN);
    IF recOk THEN
        CASE GVL_Cmd.hmiRecField OF
            1: IF (recV >= GVL_Cfg.REC_COOK_MIN)  AND (recV <= GVL_Cfg.REC_COOK_MAX)
               THEN GVL_Par.aRecipe[recIt].cookTimeS := recV;  ELSE recOk := FALSE; END_IF
            2: IF (recV >= GVL_Cfg.REC_SMDUR_MIN) AND (recV <= GVL_Cfg.REC_SMDUR_MAX)
               THEN GVL_Par.aRecipe[recIt].smashDurS := recV;  ELSE recOk := FALSE; END_IF
            3: IF (recV >= GVL_Cfg.REC_SMPOS_MIN) AND (recV <= GVL_Cfg.REC_SMPOS_MAX)
               THEN GVL_Par.aRecipe[recIt].smashPosMm := recV; ELSE recOk := FALSE; END_IF
            4: IF (recV >= GVL_Cfg.REC_HLPOS_MIN) AND (recV <= GVL_Cfg.REC_HLPOS_MAX)
               THEN GVL_Par.aRecipe[recIt].holdPosMm := recV;  ELSE recOk := FALSE; END_IF
            5: IF (recV >= GVL_Cfg.REC_PLSET_MIN) AND (recV <= GVL_Cfg.REC_PLSET_MAX)
               THEN GVL_Par.aRecipe[recIt].platenSetC := recV; ELSE recOk := FALSE; END_IF
        ELSE
            recOk := FALSE;
        END_CASE
        // physical sanity: hold gap must not be tighter than smash gap
        IF recOk AND (GVL_Par.aRecipe[recIt].holdPosMm < GVL_Par.aRecipe[recIt].smashPosMm) THEN
            GVL_Par.aRecipe[recIt].holdPosMm := GVL_Par.aRecipe[recIt].smashPosMm;
        END_IF
    END_IF
    GVL_Cmd.hmiRecAck := recOk;
    GVL_Cmd.hmiRecErr := NOT recOk;
END_IF

// ---------- press calibration trim (maintenance PIN; not while RUN) ----------
rtTrimW(CLK := GVL_Cmd.hmiTrimWrite OR ((GVL_Cmd.hmiRegsCmd[0] AND 16#0100) <> 0));
IF rtTrimW.Q THEN
    GVL_Cmd.hmiTrimAck := FALSE; GVL_Cmd.hmiTrimErr := FALSE;
    trimP := TO_INT(GVL_Cmd.hmiTrimPress);
    IF (trimP >= 0) AND (trimP <= 3)
       AND (GVL_Cmd.hmiMaintPin = MAINT_PIN)
       AND (GVL_Sts.mode <> E_MachMode.RUN)
       AND (ABS(GVL_Cmd.hmiTrimDelta) <= GVL_Cfg.PRESS_TRIM_MAX_MM) THEN
        GVL_Par.pressTrimMm[trimP] := LIMIT(-GVL_Cfg.PRESS_TRIM_MAX_MM,
            GVL_Par.pressTrimMm[trimP] + GVL_Cmd.hmiTrimDelta,
            GVL_Cfg.PRESS_TRIM_MAX_MM);
        GVL_Cmd.hmiTrimAck := TRUE;
    ELSE
        GVL_Cmd.hmiTrimErr := TRUE;
    END_IF
END_IF

// ---------- LT2100E status pack (HMI reads %MW620..669) ----------
GVL_Cmd.hmiRegsSts[0] := TO_WORD(TO_UINT(GVL_Sts.mode));
wFlags := 0;
IF GVL_Cmd.hmiRecAck    THEN wFlags := wFlags OR 16#0001; END_IF
IF GVL_Cmd.hmiRecErr    THEN wFlags := wFlags OR 16#0002; END_IF
IF GVL_Cmd.hmiTrimAck   THEN wFlags := wFlags OR 16#0004; END_IF
IF GVL_Cmd.hmiTrimErr   THEN wFlags := wFlags OR 16#0008; END_IF
IF GVL_Sts.heatAtSet    THEN wFlags := wFlags OR 16#0010; END_IF
IF GVL_Sts.fridgeAtSet  THEN wFlags := wFlags OR 16#0020; END_IF
IF GVL_Sts.allHomed     THEN wFlags := wFlags OR 16#0040; END_IF
IF GVL_Sts.safetyOk     THEN wFlags := wFlags OR 16#0080; END_IF
IF GVL_Sts.cleanCoolOk  THEN wFlags := wFlags OR 16#0100; END_IF
GVL_Cmd.hmiRegsSts[1] := wFlags;
GVL_Cmd.hmiRegsSts[2] := TO_WORD(TO_UINT(GVL_Alm.nActive));
GVL_Cmd.hmiRegsSts[3] := TO_WORD(GVL_Alm.aActive[0].id AND 16#FFFF);          // code
GVL_Cmd.hmiRegsSts[4] := TO_WORD(SHR(GVL_Alm.aActive[0].id, 16) AND 16#FFFF); // subsystem
GVL_Cmd.hmiRegsSts[5] := TO_WORD(TO_UINT(GVL_Sts.uptimeS MOD 65536));
// griddle states 626..629
FOR z2 := 0 TO 3 DO
    GVL_Cmd.hmiRegsSts[6 + z2] := TO_WORD(GVL_Sts.aGriddle[z2].state);
END_FOR
// recipe readback 630..649: per item 1..4 -> cook, smashDur, smashPos, holdPos, platenSet (all x10)
FOR it2 := 1 TO 4 DO
    base := 10 + (it2 - 1) * 5;
    GVL_Cmd.hmiRegsSts[base]     := TO_WORD(TO_UINT(GVL_Par.aRecipe[it2].cookTimeS  * 10.0));
    GVL_Cmd.hmiRegsSts[base + 1] := TO_WORD(TO_UINT(GVL_Par.aRecipe[it2].smashDurS  * 10.0));
    GVL_Cmd.hmiRegsSts[base + 2] := TO_WORD(TO_UINT(GVL_Par.aRecipe[it2].smashPosMm * 10.0));
    GVL_Cmd.hmiRegsSts[base + 3] := TO_WORD(TO_UINT(GVL_Par.aRecipe[it2].holdPosMm  * 10.0));
    GVL_Cmd.hmiRegsSts[base + 4] := TO_WORD(TO_UINT(GVL_Par.aRecipe[it2].platenSetC * 10.0));
END_FOR
// press trims 650..653 (x100 signed)
FOR z2 := 0 TO 3 DO
    GVL_Cmd.hmiRegsSts[30 + z2] := TO_WORD(TO_INT(GVL_Par.pressTrimMm[z2] * 100.0));
END_FOR
// temperatures 654..661 platens, 662 fridge (x10)
FOR z2 := 0 TO 7 DO
    GVL_Cmd.hmiRegsSts[34 + z2] := TO_WORD(TO_INT(GVL_Sts.aHeat[z2].actC * 10.0));
END_FOR
GVL_Cmd.hmiRegsSts[42] := TO_WORD(TO_INT(GVL_Sts.fridgeActC * 10.0));

IF NOT init THEN
    init := TRUE;
    FOR i := 0 TO 3 DO
        GVL_Mech.drvPress[i].SubsysId := GVL_Cfg.SS_PRESS_0 + TO_UINT(i);
        GVL_Mech.fbPress[i].PressId := i;
    END_FOR
    GVL_Mech.fbDoorFridgeFront.SubsysId := GVL_Cfg.SS_AIRLOCK;
    GVL_Mech.fbDoorFridgeSide.SubsysId  := GVL_Cfg.SS_AIRLOCK;
    GVL_Mech.fbDoorChamber.SubsysId     := GVL_Cfg.SS_AIRLOCK;
    GVL_Mech.fbPinGriddle.SubsysId := GVL_Cfg.SS_GRID_CAR;
    GVL_Mech.fbPinFridge.SubsysId  := GVL_Cfg.SS_FRIDGE_CAR;
    GVL_Mech.fbPneuGrip.SubsysId   := GVL_Cfg.SS_GRIPPER;
    GVL_Mech.vfdGriddle.SubsysId := GVL_Cfg.SS_GRID_CAR;
    GVL_Mech.vfdFridge.SubsysId  := GVL_Cfg.SS_FRIDGE_CAR;
END_IF

// ---- presses ----
FOR i := 0 TO 3 DO
    GVL_Mech.fbPress[i].Enable := GVL_Sts.enMotion;
    GVL_Mech.fbPress[i].Abort  := GVL_Sts.abortAll;
    GVL_Mech.fbPress[i].Sim    := GVL_Cfg.SIM_MODE;
    GVL_Mech.fbPress[i].CycleMs:= GVL_Cfg.T_APP_MS;
    GVL_Mech.drvPress[i].Sim    := GVL_Cfg.SIM_MODE;
    GVL_Mech.drvPress[i].Enable := GVL_Sts.enMotion;
    GVL_Mech.drvPress[i].Abort  := GVL_Sts.abortAll;
    GVL_Mech.drvPress[i].CycleMs:= GVL_Cfg.T_APP_MS;
    GVL_Mech.drvPress[i].iInPos := GVL_IO.iPressInPos[i];
    GVL_Mech.drvPress[i].iAlarm := GVL_IO.iPressAlarm[i];
    GVL_Mech.fbPress[i](Drv := GVL_Mech.drvPress[i]);
    GVL_Mech.drvPress[i]();
    IF NOT GVL_Cfg.SIM_MODE THEN
        GVL_IO.qPressSel0[i]   := GVL_Mech.drvPress[i].qSel0;
        GVL_IO.qPressSel1[i]   := GVL_Mech.drvPress[i].qSel1;
        GVL_IO.qPressCtrg[i]   := GVL_Mech.drvPress[i].qCtrg;
        GVL_IO.qPressEnable[i] := GVL_Mech.drvPress[i].qEnable;
    END_IF
END_FOR

// ---- CS2RS Modbus RTU transport for PR parameter writes ----
// Active when NOT SIM_MODE, or when GVL_Cfg.PRESS_MB_REAL (bench test with a
// real drive while the rest of the machine is simulated).
// The drive FB emits a generic single-register write request:
//   drvPress[i].MbWrExec (held TRUE), .MbSlave, .MbAddr, .MbValue
// and expects .MbWrDone / .MbWrErr back.
//
// TODO(TRANSPORT): instantiate the LS_ModbusMasterlib write FB here — open
// Library Manager -> LS_ModbusMasterlib and use its write-single-register
// block (v0: serve drvPress[0] only; arbitrate 0..3 round-robin later):
//
//   mbWr( Execute  := GVL_Mech.drvPress[0].MbWrExec,
//         SlaveId  := GVL_Mech.drvPress[0].MbSlave,      // 1
//         RegAddr  := GVL_Mech.drvPress[0].MbAddr,
//         RegValue := GVL_Mech.drvPress[0].MbValue );
//   GVL_Mech.drvPress[0].MbWrDone := mbWr.Done;
//   GVL_Mech.drvPress[0].MbWrErr  := mbWr.Error;
//
// (exact FB/pin names differ per library version — paste the library's FB
// list and finish this in one edit)

// ---- pneumatics ----
GVL_Mech.fbDoorFridgeSide(Sim := GVL_Cfg.SIM_MODE, CycleMs := GVL_Cfg.T_APP_MS,
    iExtended := GVL_IO.iDoorFrSide_Op, iRetracted := GVL_IO.iDoorFrSide_Cl);
GVL_Mech.fbDoorChamber(Sim := GVL_Cfg.SIM_MODE, CycleMs := GVL_Cfg.T_APP_MS,
    iExtended := GVL_IO.iDoorChamber_Op, iRetracted := GVL_IO.iDoorChamber_Cl);
GVL_Mech.fbDoorFridgeFront(Sim := GVL_Cfg.SIM_MODE, CycleMs := GVL_Cfg.T_APP_MS,
    iExtended := GVL_IO.iDoorFrFront_Op, iRetracted := GVL_IO.iDoorFrFront_Cl);
GVL_Mech.fbPinGriddle(Sim := GVL_Cfg.SIM_MODE, CycleMs := GVL_Cfg.T_APP_MS,
    iExtended := GVL_IO.iPinGriddle_Ext, iRetracted := GVL_IO.iPinGriddle_Ret);
GVL_Mech.fbPinFridge(Sim := GVL_Cfg.SIM_MODE, CycleMs := GVL_Cfg.T_APP_MS,
    iExtended := GVL_IO.iPinFridge_Ext, iRetracted := GVL_IO.iPinFridge_Ret);
GVL_Mech.fbPneuGrip(Sim := GVL_Cfg.SIM_MODE, CycleMs := GVL_Cfg.T_APP_MS,
    iExtended := GVL_IO.iGripAcquired, iRetracted := NOT GVL_IO.iGripAcquired);
IF NOT GVL_Cfg.SIM_MODE THEN
    GVL_IO.qDoorFridgeSide  := GVL_Mech.fbDoorFridgeSide.qValve;
    GVL_IO.qDoorChamber     := GVL_Mech.fbDoorChamber.qValve;
    GVL_IO.qDoorFridgeFront := GVL_Mech.fbDoorFridgeFront.qValve;
    GVL_IO.qPinGriddle      := GVL_Mech.fbPinGriddle.qValve;
    GVL_IO.qPinFridge       := GVL_Mech.fbPinFridge.qValve;
    GVL_IO.qGripper         := GVL_Mech.fbPneuGrip.qValve;
END_IF

// ---- airlock ----
GVL_Mech.fbAirlock(
    Enable := GVL_Sts.enMotion, Abort := GVL_Sts.abortAll,
    DoorFridge := GVL_Mech.fbDoorFridgeSide,
    DoorChamber := GVL_Mech.fbDoorChamber);

// ---- carousels ----
GVL_Mech.vfdGriddle.Sim := GVL_Cfg.SIM_MODE;  GVL_Mech.vfdGriddle.CycleMs := GVL_Cfg.T_APP_MS;
GVL_Mech.vfdGriddle.iEnc := GVL_IO.diGridCarEnc;
GVL_Mech.vfdGriddle.iHomeProx := GVL_IO.iGridCarHome;
GVL_Mech.vfdFridge.Sim := GVL_Cfg.SIM_MODE;   GVL_Mech.vfdFridge.CycleMs := GVL_Cfg.T_APP_MS;
GVL_Mech.vfdFridge.iEnc := GVL_IO.diFrCarEnc;
GVL_Mech.vfdFridge.iHomeProx := GVL_IO.iFrCarHome;

GVL_Mech.fbGridCar(
    Enable := GVL_Sts.enMotion, Abort := GVL_Sts.abortAll,
    Vfd := GVL_Mech.vfdGriddle, Pin := GVL_Mech.fbPinGriddle);
GVL_Mech.fbFridgeCar(
    Enable := GVL_Sts.enMotion, Abort := GVL_Sts.abortAll,
    Vfd := GVL_Mech.vfdFridge, Pin := GVL_Mech.fbPinFridge);
GVL_Mech.vfdGriddle();
GVL_Mech.vfdFridge();
IF NOT GVL_Cfg.SIM_MODE THEN
    GVL_IO.qGridCarFwd := GVL_Mech.vfdGriddle.qFwd;
    GVL_IO.qGridCarRev := GVL_Mech.vfdGriddle.qRev;
    GVL_IO.wGridCarSpeed := GVL_Mech.vfdGriddle.qSpeed;
    GVL_IO.qFrCarFwd := GVL_Mech.vfdFridge.qFwd;
    GVL_IO.qFrCarRev := GVL_Mech.vfdFridge.qRev;
    GVL_IO.wFrCarSpeed := GVL_Mech.vfdFridge.qSpeed;
END_IF
GVL_Sts.carGridStation := GVL_Mech.fbGridCar.ActStation;
GVL_Sts.carFridgeFace  := GVL_Mech.fbFridgeCar.ActFace;

FOR z := 0 TO 7 DO
    g := z / 2;
    itm := GVL_Sts.aGriddle[g].item;
    IF itm = 0 THEN itm := 1; END_IF          // idle at BEEF setpoint
    setC := GVL_Par.aRecipe[itm].platenSetC;
    GVL_Mech.fbHeater[z].Sim := GVL_Cfg.SIM_MODE;
    GVL_Mech.fbHeater[z].ZoneId := z;
    GVL_Mech.fbHeater[z].CycleMs := GVL_Cfg.T_APP_MS;
    GVL_Mech.fbHeater[z].Enable := GVL_Sts.enProcess;
    GVL_Mech.fbHeater[z].SetC := setC;
    GVL_Mech.fbHeater[z].iTempRaw := GVL_IO.wPlatenTemp[z];
    GVL_Mech.fbHeater[z].StaggerToken := GVL_Mech.fbHeatBank.Token[z];
    GVL_Mech.fbHeater[z]();
    IF NOT GVL_Cfg.SIM_MODE THEN
        GVL_IO.qSsr[z] := GVL_Mech.fbHeater[z].qSsr;
    END_IF
    GVL_Sts.aHeat[z] := GVL_Mech.fbHeater[z].Zone;
END_FOR
GVL_Mech.fbHeatBank(Enable := GVL_Sts.enProcess, Heaters := GVL_Mech.fbHeater);

GVL_Mech.fbRefrig(
    Sim := GVL_Cfg.SIM_MODE,
    Enable := GVL_Sts.enProcess,
    iTempRaw := GVL_IO.wFridgeTemp,
    CycleMs := GVL_Cfg.T_APP_MS);
// (compressor output relay would be copied to GVL_IO here at migration)

msAcc := msAcc + GVL_Cfg.T_APP_MS;
IF msAcc >= 1000.0 THEN
    msAcc := msAcc - 1000.0;
    GVL_Sts.uptimeS := GVL_Sts.uptimeS + 1;
END_IF
// TODO(commissioning): add per-signal force flags here, e.g.
//   IF forceDoorChamber THEN GVL_IO.qDoorChamber := forceVal; END_IF

IF NOT init THEN
    init := TRUE;
    GVL_Mech.axGX.SubsysId := GVL_Cfg.SS_GANTRY_X;   GVL_Mech.axGX.CycleMs := GVL_Cfg.T_MOTION_MS;
    GVL_Mech.axGT.SubsysId := GVL_Cfg.SS_GANTRY_T;   GVL_Mech.axGT.CycleMs := GVL_Cfg.T_MOTION_MS;
    GVL_Mech.axGZ.SubsysId := GVL_Cfg.SS_GANTRY_Z;   GVL_Mech.axGZ.CycleMs := GVL_Cfg.T_MOTION_MS;
    GVL_Mech.axSX.SubsysId := GVL_Cfg.SS_SCRAPER_X;  GVL_Mech.axSX.CycleMs := GVL_Cfg.T_MOTION_MS;
    GVL_Mech.axSY.SubsysId := GVL_Cfg.SS_SCRAPER_Y;  GVL_Mech.axSY.CycleMs := GVL_Cfg.T_MOTION_MS;
    GVL_Mech.axSZ.SubsysId := GVL_Cfg.SS_SCRAPER_Z;  GVL_Mech.axSZ.CycleMs := GVL_Cfg.T_MOTION_MS;
    GVL_Mech.axFZ.SubsysId := GVL_Cfg.SS_FORK_Z;     GVL_Mech.axFZ.CycleMs := GVL_Cfg.T_MOTION_MS;
    GVL_Mech.axFT.SubsysId := GVL_Cfg.SS_FORK_TELE;  GVL_Mech.axFT.CycleMs := GVL_Cfg.T_MOTION_MS;
END_IF

// ---- distribute enables / abort / reset ----
GVL_Mech.axGX.Sim := GVL_Cfg.SIM_MODE;  GVL_Mech.axGX.Enable := GVL_Sts.enMotion;
GVL_Mech.axGT.Sim := GVL_Cfg.SIM_MODE;  GVL_Mech.axGT.Enable := GVL_Sts.enMotion;
GVL_Mech.axGZ.Sim := GVL_Cfg.SIM_MODE;  GVL_Mech.axGZ.Enable := GVL_Sts.enMotion;
GVL_Mech.axSX.Sim := GVL_Cfg.SIM_MODE;  GVL_Mech.axSX.Enable := GVL_Sts.enMotion;
GVL_Mech.axSY.Sim := GVL_Cfg.SIM_MODE;  GVL_Mech.axSY.Enable := GVL_Sts.enMotion;
GVL_Mech.axSZ.Sim := GVL_Cfg.SIM_MODE;  GVL_Mech.axSZ.Enable := GVL_Sts.enMotion;
GVL_Mech.axFZ.Sim := GVL_Cfg.SIM_MODE;  GVL_Mech.axFZ.Enable := GVL_Sts.enMotion;
GVL_Mech.axFT.Sim := GVL_Cfg.SIM_MODE;  GVL_Mech.axFT.Enable := GVL_Sts.enMotion;
GVL_Mech.axGX.Abort := GVL_Sts.abortAll;  GVL_Mech.axGX.ResetExec := GVL_Sts.resetPulse;
GVL_Mech.axGT.Abort := GVL_Sts.abortAll;  GVL_Mech.axGT.ResetExec := GVL_Sts.resetPulse;
GVL_Mech.axGZ.Abort := GVL_Sts.abortAll;  GVL_Mech.axGZ.ResetExec := GVL_Sts.resetPulse;
GVL_Mech.axSX.Abort := GVL_Sts.abortAll;  GVL_Mech.axSX.ResetExec := GVL_Sts.resetPulse;
GVL_Mech.axSY.Abort := GVL_Sts.abortAll;  GVL_Mech.axSY.ResetExec := GVL_Sts.resetPulse;
GVL_Mech.axSZ.Abort := GVL_Sts.abortAll;  GVL_Mech.axSZ.ResetExec := GVL_Sts.resetPulse;
GVL_Mech.axFZ.Abort := GVL_Sts.abortAll;  GVL_Mech.axFZ.ResetExec := GVL_Sts.resetPulse;
GVL_Mech.axFT.Abort := GVL_Sts.abortAll;  GVL_Mech.axFT.ResetExec := GVL_Sts.resetPulse;

// ---- mechanism bodies (write axis inputs) ----
GVL_Mech.fbGripper(
    Sim  := GVL_Cfg.SIM_MODE,
    iAcquired := GVL_IO.iGripAcquired,
    Pneu := GVL_Mech.fbPneuGrip);

GVL_Mech.fbGantry(
    Enable := GVL_Sts.enMotion,
    Abort  := GVL_Sts.abortAll,
    Sim    := GVL_Cfg.SIM_MODE,
    AxX := GVL_Mech.axGX, AxT := GVL_Mech.axGT, AxZ := GVL_Mech.axGZ,
    Grip := GVL_Mech.fbGripper, IK := GVL_Mech.fbIK);

GVL_Mech.fbScraper(
    Enable := GVL_Sts.enMotion,
    Abort  := GVL_Sts.abortAll,
    Sim    := GVL_Cfg.SIM_MODE,
    AxX := GVL_Mech.axSX, AxY := GVL_Mech.axSY, AxZ := GVL_Mech.axSZ);

GVL_Mech.fbFork(
    Enable := GVL_Sts.enMotion,
    Abort  := GVL_Sts.abortAll,
    Sim    := GVL_Cfg.SIM_MODE,
    iBrakeOk := GVL_IO.iForkBrakeOk,
    iTrayPresent := GVL_IO.iForkTrayPresent,
    AxZ := GVL_Mech.axFZ, AxT := GVL_Mech.axFT);
IF NOT GVL_Cfg.SIM_MODE THEN
    GVL_IO.qForkBrakeRelease := GVL_Mech.fbFork.qBrakeRelease;
END_IF

// ---- axis bodies LAST (consume inputs written above) ----
GVL_Mech.axGX(Axis := GVL_Axes.axRefGantryX);
GVL_Mech.axGT(Axis := GVL_Axes.axRefGantryT);
GVL_Mech.axGZ(Axis := GVL_Axes.axRefGantryZ);
GVL_Mech.axSX(Axis := GVL_Axes.axRefScraperX);
GVL_Mech.axSY(Axis := GVL_Axes.axRefScraperY);
GVL_Mech.axSZ(Axis := GVL_Axes.axRefScraperZ);
GVL_Mech.axFZ(Axis := GVL_Axes.axRefForkZ);
GVL_Mech.axFT(Axis := GVL_Axes.axRefForkTele);

rtStart(CLK := GVL_Cmd.testStart);
IF rtStart.Q AND NOT running THEN
    running := TRUE; suiteDone := FALSE;
    FOR i := 1 TO 10 DO aResult[i] := 0; aFailCode[i] := 0; END_FOR
    PassCount := 0;
    tc := 1; stp := 0;
END_IF
IF NOT running THEN RETURN; END_IF

// keep simulated gateway heartbeat alive during the whole suite
hbDiv := hbDiv + 1;
IF hbDiv >= 25 THEN   // every 500 ms
    hbDiv := 0; hbCnt := hbCnt + 1;
    GVL_Cmd.mbCmdRegs[9] := hbCnt;
END_IF

// per-step guard
tonG(IN := TRUE, PT := ptCur);

CASE tc OF
// ================= TC1: boot -> READY =================
1:
    CASE stp OF
        0: ptCur := T#90S; tonG(IN := FALSE); stp := 1;
        1:
            IF (GVL_Sts.mode = E_MachMode.READY) AND GVL_Sts.allHomed THEN
                aResult[1] := 1; tc := 2; stp := 0;
            ELSIF tonG.Q THEN
                aResult[1] := 2; aFailCode[1] := TO_UDINT(TO_UINT(GVL_Sts.mode));
                tc := 2; stp := 0;
            END_IF
    END_CASE

// ================= TC2: IK table =================
2:
    ikFail := FALSE;
    FOR i := 0 TO GVL_Cfg.PATTIES_PER_TRAY - 1 DO
        px := GVL_Cfg.PICK_BASE_X + TO_LREAL(i MOD GVL_Cfg.TRAY_COLS) * GVL_Cfg.PICK_SPACING_X;
        py := GVL_Cfg.PICK_BASE_Y + TO_LREAL(i / GVL_Cfg.TRAY_COLS) * GVL_Cfg.PICK_SPACING_Y;
        GVL_Mech.fbIK(xCart := px, yCart := py);
        IF NOT GVL_Mech.fbIK.Reachable THEN ikFail := TRUE; aFailCode[2] := TO_UDINT(TO_UINT(i)); END_IF
        thR := GVL_Mech.fbIK.thetaDeg * PI_ / 180.0;
        xr := GVL_Mech.fbIK.xLin + GVL_Cfg.ARM_LEN * COS(thR);
        yr := GVL_Cfg.ARM_LEN * SIN(thR);
        IF (ABS(xr - px) > 0.01) OR (ABS(yr - py) > 0.01) THEN
            ikFail := TRUE; aFailCode[2] := 1000 + TO_UDINT(TO_UINT(i));
        END_IF
    END_FOR
    FOR i := 0 TO GVL_Cfg.PATTIES_PER_GRIDDLE - 1 DO
        px := GVL_Cfg.PLACE_BASE_X + TO_LREAL(i MOD GVL_Cfg.PLACE_COLS) * GVL_Cfg.PLACE_SPC_X;
        py := GVL_Cfg.PLACE_BASE_Y + TO_LREAL(i / GVL_Cfg.PLACE_COLS) * GVL_Cfg.PLACE_SPC_Y;
        GVL_Mech.fbIK(xCart := px, yCart := py);
        IF NOT GVL_Mech.fbIK.Reachable THEN ikFail := TRUE; aFailCode[2] := 2000 + TO_UDINT(TO_UINT(i)); END_IF
    END_FOR
    IF ikFail THEN aResult[2] := 2; ELSE aResult[2] := 1; END_IF
    tc := 3; stp := 0;

// ================= TC3: heat + fridge + stagger =================
3:
    CASE stp OF
        0: ptCur := T#240S; tonG(IN := FALSE); stagViol := FALSE; stp := 1;
        1:
            // stagger monitor: count zones actively ramping WITH token
            nRamp := 0;
            FOR i := 0 TO 7 DO
                IF GVL_Mech.fbHeatBank.Token[i]
                   AND ((GVL_Sts.aHeat[i].setC - GVL_Sts.aHeat[i].actC) > 20.0) THEN
                    nRamp := nRamp + 1;
                END_IF
            END_FOR
            IF nRamp > GVL_Cfg.HEAT_MAX_STAGGER THEN stagViol := TRUE; END_IF
            IF GVL_Sts.heatAtSet AND GVL_Sts.fridgeAtSet THEN
                IF stagViol THEN aResult[3] := 2; aFailCode[3] := 1;
                ELSE aResult[3] := 1; END_IF
                tc := 4; stp := 0;
            ELSIF tonG.Q THEN
                aResult[3] := 2; aFailCode[3] := 2;
                tc := 4; stp := 0;
            END_IF
    END_CASE

// ================= TC4: airlock mutual exclusion =================
4:
    CASE stp OF
        0:
            ptCur := T#10S; tonG(IN := FALSE);
            GVL_Mech.fbAirlock.ReqFridgeOpen := TRUE;
            stp := 1;
        1:
            IF GVL_Mech.fbAirlock.FridgeOpen THEN
                GVL_Mech.fbAirlock.ReqChamberOpen := TRUE;  // request BOTH
                tonG(IN := FALSE); stp := 2;
            ELSIF tonG.Q THEN stp := 90; END_IF
        2: // hold both requests 2 s; invariant must hold
            IF GVL_Mech.fbAirlock.FridgeOpen AND GVL_Mech.fbAirlock.ChamberOpen THEN stp := 90; END_IF
            IF tonG.ET >= T#2S THEN
                GVL_Mech.fbAirlock.ReqFridgeOpen := FALSE;   // yield to chamber
                tonG(IN := FALSE); stp := 3;
            END_IF
        3:
            IF GVL_Mech.fbAirlock.FridgeOpen AND GVL_Mech.fbAirlock.ChamberOpen THEN stp := 90; END_IF
            IF GVL_Mech.fbAirlock.ChamberOpen THEN
                GVL_Mech.fbAirlock.ReqChamberOpen := FALSE;
                tonG(IN := FALSE); stp := 4;
            ELSIF tonG.Q THEN stp := 90; END_IF
        4:
            IF GVL_Mech.fbAirlock.ChamberSealed THEN
                aResult[4] := 1; tc := 5; stp := 0;
            ELSIF tonG.Q THEN stp := 90; END_IF
        90:
            GVL_Mech.fbAirlock.ReqFridgeOpen := FALSE;
            GVL_Mech.fbAirlock.ReqChamberOpen := FALSE;
            aResult[4] := 2; aFailCode[4] := TO_UDINT(TO_UINT(stp));
            tc := 5; stp := 0;
    END_CASE

// ================= TC5: press profile =================
5:
    CASE stp OF
        0:
            ptCur := T#20S; tonG(IN := FALSE);
            GVL_Mech.fbPress[0].Recipe := GVL_Par.aRecipe[1];   // BEEF
            GVL_Mech.fbPress[0].Cmd.code := GVL_Cfg.MCMD_PROFILE;
            GVL_Mech.fbPress[0].CmdExec := TRUE;
            stp := 1;
        1:
            IF GVL_Mech.fbPress[0].Holding THEN
                GVL_Mech.fbPress[0].CmdExec := FALSE;
                IF GVL_Mech.fbPress[0].DwellS < GVL_Par.aRecipe[1].smashDurS - 1.0 THEN
                    aFailCode[5] := 1; stp := 90;
                ELSE
                    GVL_Mech.fbPress[0].Cmd.code := GVL_Cfg.MCMD_OPEN;
                    tonG(IN := FALSE); stp := 12;   // one-scan gap: R_TRIG needs FALSE->TRUE across scans
                END_IF
            ELSIF GVL_Mech.fbPress[0].Error OR tonG.Q THEN
                GVL_Mech.fbPress[0].CmdExec := FALSE;
                aFailCode[5] := GVL_Mech.fbPress[0].ErrorID; stp := 90;
            END_IF
        12: // re-arm on a fresh scan
            GVL_Mech.fbPress[0].CmdExec := TRUE;
            stp := 2;
        2:
            IF GVL_Mech.fbPress[0].IsOpen THEN
                GVL_Mech.fbPress[0].CmdExec := FALSE;
                aResult[5] := 1; tc := 6; stp := 0;
            ELSIF GVL_Mech.fbPress[0].Error OR tonG.Q THEN
                GVL_Mech.fbPress[0].CmdExec := FALSE;
                aFailCode[5] := GVL_Mech.fbPress[0].ErrorID; stp := 90;
            END_IF
        90:
            aResult[5] := 2; tc := 6; stp := 0;
    END_CASE

// ================= TC6: griddle carousel =================
6:
    CASE stp OF
        0: // park gantry first so rotation permissive is TRUE
            ptCur := T#20S; tonG(IN := FALSE);
            GVL_Mech.fbGantry.Cmd.code := GVL_Cfg.MCMD_PARK;
            GVL_Mech.fbGantry.CmdExec := TRUE;
            stp := 1;
        1:
            IF GVL_Mech.fbGantry.Done AND GVL_Mech.fbGantry.Parked THEN
                GVL_Mech.fbGantry.CmdExec := FALSE; k := 0;
                tonG(IN := FALSE); stp := 2;
            ELSIF GVL_Mech.fbGantry.Error OR tonG.Q THEN
                GVL_Mech.fbGantry.CmdExec := FALSE;
                aFailCode[6] := GVL_Mech.fbGantry.ErrorID; stp := 90;
            END_IF
        2: // sequence of targets 1, 3, 0
            CASE k OF 0: i := 1; 1: i := 3; 2: i := 0; END_CASE
            GVL_Mech.fbGridCar.TargetStation := i;
            GVL_Mech.fbGridCar.GotoExec := TRUE;
            tonG(IN := FALSE); stp := 3;
        3:
            IF GVL_Mech.fbGridCar.Done AND (GVL_Mech.fbGridCar.ActStation = i) THEN
                GVL_Mech.fbGridCar.GotoExec := FALSE;
                k := k + 1;
                IF k >= 3 THEN aResult[6] := 1; tc := 7; stp := 0;
                ELSE stp := 2; END_IF
            ELSIF GVL_Mech.fbGridCar.Error OR tonG.Q THEN
                GVL_Mech.fbGridCar.GotoExec := FALSE;
                aFailCode[6] := GVL_Mech.fbGridCar.ErrorID; stp := 90;
            END_IF
        90:
            aResult[6] := 2; tc := 7; stp := 0;
    END_CASE

// ================= TC7: fork fetch / return =================
7:
    CASE stp OF
        0:
            ptCur := T#40S; tonG(IN := FALSE);
            GVL_Mech.fbFork.Cmd.code := GVL_Cfg.MCMD_FETCH;
            GVL_Mech.fbFork.Cmd.p1 := 5.0;
            GVL_Mech.fbFork.CmdExec := TRUE;
            stp := 1;
        1:
            IF GVL_Mech.fbFork.Done AND GVL_Mech.fbFork.TrayHeld THEN
                GVL_Mech.fbFork.CmdExec := FALSE;
                GVL_Mech.fbFork.Cmd.code := GVL_Cfg.MCMD_RETURN;
                GVL_Mech.fbFork.Cmd.p1 := 5.0;
                tonG(IN := FALSE); stp := 12;   // one-scan gap for a real edge
            ELSIF GVL_Mech.fbFork.Error OR tonG.Q THEN
                GVL_Mech.fbFork.CmdExec := FALSE;
                aFailCode[7] := GVL_Mech.fbFork.ErrorID; stp := 90;
            END_IF
        12: // re-arm on a fresh scan
            GVL_Mech.fbFork.CmdExec := TRUE;
            stp := 2;
        2:
            IF GVL_Mech.fbFork.Done AND NOT GVL_Mech.fbFork.TrayHeld THEN
                GVL_Mech.fbFork.CmdExec := FALSE;
                aResult[7] := 1; tc := 8; stp := 0;
            ELSIF GVL_Mech.fbFork.Error OR tonG.Q THEN
                GVL_Mech.fbFork.CmdExec := FALSE;
                aFailCode[7] := GVL_Mech.fbFork.ErrorID; stp := 90;
            END_IF
        90:
            aResult[7] := 2; tc := 8; stp := 0;
    END_CASE

// ================= TC8: gantry pick / place / park =================
8:
    CASE stp OF
        0:
            ptCur := T#30S; tonG(IN := FALSE);
            GVL_Mech.fbGantry.Cmd.code := GVL_Cfg.MCMD_PICK;
            GVL_Mech.fbGantry.Cmd.p1 := 0.0;
            GVL_Mech.fbGantry.CmdExec := TRUE;
            stp := 1;
        1:
            IF GVL_Mech.fbGantry.Done AND GVL_Mech.fbGripper.Holding THEN
                GVL_Mech.fbGantry.CmdExec := FALSE;
                GVL_Mech.fbGantry.Cmd.code := GVL_Cfg.MCMD_PLACE;
                GVL_Mech.fbGantry.Cmd.p1 := 0.0;
                tonG(IN := FALSE); stp := 12;   // one-scan gap for a real edge
            ELSIF GVL_Mech.fbGantry.Error OR tonG.Q THEN
                GVL_Mech.fbGantry.CmdExec := FALSE;
                aFailCode[8] := GVL_Mech.fbGantry.ErrorID; stp := 90;
            END_IF
        2:
            IF GVL_Mech.fbGantry.Done AND NOT GVL_Mech.fbGripper.Holding THEN
                GVL_Mech.fbGantry.CmdExec := FALSE;
                GVL_Mech.fbGantry.Cmd.code := GVL_Cfg.MCMD_PARK;
                tonG(IN := FALSE); stp := 13;   // one-scan gap for a real edge
            ELSIF GVL_Mech.fbGantry.Error OR tonG.Q THEN
                GVL_Mech.fbGantry.CmdExec := FALSE;
                aFailCode[8] := GVL_Mech.fbGantry.ErrorID; stp := 90;
            END_IF
        12: // re-arm PLACE on a fresh scan
            GVL_Mech.fbGantry.CmdExec := TRUE;
            stp := 2;
        13: // re-arm PARK on a fresh scan
            GVL_Mech.fbGantry.CmdExec := TRUE;
            stp := 3;
        3:
            IF GVL_Mech.fbGantry.Done AND GVL_Mech.fbGantry.Parked THEN
                GVL_Mech.fbGantry.CmdExec := FALSE;
                aResult[8] := 1; tc := 9; stp := 0;
            ELSIF GVL_Mech.fbGantry.Error OR tonG.Q THEN
                GVL_Mech.fbGantry.CmdExec := FALSE;
                aFailCode[8] := GVL_Mech.fbGantry.ErrorID; stp := 90;
            END_IF
        90:
            aResult[8] := 2; tc := 9; stp := 0;
    END_CASE

// ================= TC9: full cycle via Gateway registers =================
9:
    CASE stp OF
        0: // enter RUN through the real path — but first wait for thermal readiness
           // (fridge pulldown / heat-up gate READY->RUN; on a fast suite run they
           //  may not be satisfied yet)
            GVL_Cmd.testMode := FALSE;
            haccp0 := GVL_Sts.haccpCount;
            ptCur := T#300S; tonG(IN := FALSE); stp := 30;
        30:
            IF GVL_Sts.heatAtSet AND GVL_Sts.fridgeAtSet AND GVL_Sts.allHomed THEN
                GVL_Cmd.reqStart := TRUE; holdCnt := 0;
                ptCur := T#20S; tonG(IN := FALSE); stp := 1;
            ELSIF tonG.Q THEN aFailCode[9] := 30; stp := 90; END_IF
        1:
            holdCnt := holdCnt + 1;
            IF holdCnt > 5 THEN GVL_Cmd.reqStart := FALSE; END_IF
            IF holdCnt > 10 THEN GVL_Cmd.reqStart := TRUE; holdCnt := 0; END_IF  // retry edge (one-shot may be rejected)
            IF GVL_Sts.mode = E_MachMode.RUN THEN
                GVL_Cmd.reqStart := FALSE; stp := 2;
            ELSIF tonG.Q THEN aFailCode[9] := 1; stp := 90; END_IF
        2: // FETCH_TRAY item=1 level=3 face=0
            testSeq := testSeq + 1;
            GVL_Cmd.mbCmdRegs[0] := testSeq;
            GVL_Cmd.mbCmdRegs[1] := GVL_Cfg.CMD_FETCH_TRAY;
            GVL_Cmd.mbCmdRegs[2] := 1;  GVL_Cmd.mbCmdRegs[3] := 0;   // p1 item
            GVL_Cmd.mbCmdRegs[4] := 3;  GVL_Cmd.mbCmdRegs[5] := 0;   // p2 level
            GVL_Cmd.mbCmdRegs[6] := 0;  GVL_Cmd.mbCmdRegs[7] := 0;   // p3 face
            ptCur := T#60S; tonG(IN := FALSE); stp := 3;
        3:
            IF (GVL_Cmd.gwAck.seqEcho = testSeq) AND GVL_Cmd.gwAck.done THEN stp := 4;
            ELSIF (GVL_Cmd.gwAck.seqEcho = testSeq) AND GVL_Cmd.gwAck.error THEN
                aFailCode[9] := GVL_Cmd.gwAck.errorId; stp := 90;
            ELSIF tonG.Q THEN aFailCode[9] := 3; stp := 90; END_IF
        4: // LOAD_GRIDDLE g=0 count=2 item=1
            testSeq := testSeq + 1;
            GVL_Cmd.mbCmdRegs[0] := testSeq;
            GVL_Cmd.mbCmdRegs[1] := GVL_Cfg.CMD_LOAD_GRIDDLE;
            GVL_Cmd.mbCmdRegs[2] := 0;  GVL_Cmd.mbCmdRegs[3] := 0;
            GVL_Cmd.mbCmdRegs[4] := 2;  GVL_Cmd.mbCmdRegs[5] := 0;
            GVL_Cmd.mbCmdRegs[6] := 1;  GVL_Cmd.mbCmdRegs[7] := 0;
            ptCur := T#120S; tonG(IN := FALSE); stp := 5;
        5:
            IF (GVL_Cmd.gwAck.seqEcho = testSeq) AND GVL_Cmd.gwAck.done THEN stp := 6;
            ELSIF (GVL_Cmd.gwAck.seqEcho = testSeq) AND GVL_Cmd.gwAck.error THEN
                aFailCode[9] := GVL_Cmd.gwAck.errorId; stp := 90;
            ELSIF tonG.Q THEN aFailCode[9] := 5; stp := 90; END_IF
        6: // wait cook done (90 s scaled by 5 -> ~18 s real)
            ptCur := T#120S; tonG(IN := FALSE); stp := 7;
        7:
            IF GVL_Sts.aGriddle[0].state = TO_UINT(E_GriddleState.READY_TO_SCRAPE) THEN stp := 8;
            ELSIF tonG.Q THEN aFailCode[9] := 7; stp := 90; END_IF
        8: // SCRAPE g=0
            testSeq := testSeq + 1;
            GVL_Cmd.mbCmdRegs[0] := testSeq;
            GVL_Cmd.mbCmdRegs[1] := GVL_Cfg.CMD_SCRAPE;
            GVL_Cmd.mbCmdRegs[2] := 0;  GVL_Cmd.mbCmdRegs[3] := 0;
            GVL_Cmd.mbCmdRegs[4] := 0;  GVL_Cmd.mbCmdRegs[6] := 0;
            ptCur := T#90S; tonG(IN := FALSE); stp := 9;
        9:
            IF (GVL_Cmd.gwAck.seqEcho = testSeq) AND GVL_Cmd.gwAck.done THEN stp := 10;
            ELSIF (GVL_Cmd.gwAck.seqEcho = testSeq) AND GVL_Cmd.gwAck.error THEN
                aFailCode[9] := GVL_Cmd.gwAck.errorId; stp := 90;
            ELSIF tonG.Q THEN aFailCode[9] := 9; stp := 90; END_IF
        10: // RETURN_TRAY level=3 face=0
            testSeq := testSeq + 1;
            GVL_Cmd.mbCmdRegs[0] := testSeq;
            GVL_Cmd.mbCmdRegs[1] := GVL_Cfg.CMD_RETURN_TRAY;
            GVL_Cmd.mbCmdRegs[2] := 3;  GVL_Cmd.mbCmdRegs[3] := 0;
            GVL_Cmd.mbCmdRegs[4] := 0;  GVL_Cmd.mbCmdRegs[5] := 0;
            ptCur := T#60S; tonG(IN := FALSE); stp := 11;
        11:
            IF (GVL_Cmd.gwAck.seqEcho = testSeq) AND GVL_Cmd.gwAck.done THEN
                // HACCP record must exist and be clean
                IF (GVL_Sts.haccpCount = haccp0 + 1) AND (GVL_Sts.lastHaccp.result = 0) THEN
                    aResult[9] := 1;
                ELSE
                    aResult[9] := 2; aFailCode[9] := 11;
                END_IF
                GVL_Cmd.testMode := TRUE;
                tc := 10; stp := 0;
            ELSIF (GVL_Cmd.gwAck.seqEcho = testSeq) AND GVL_Cmd.gwAck.error THEN
                aFailCode[9] := GVL_Cmd.gwAck.errorId; stp := 90;
            ELSIF tonG.Q THEN aFailCode[9] := 12; stp := 90; END_IF
        90:
            GVL_Cmd.testMode := TRUE;
            aResult[9] := 2; tc := 10; stp := 0;
    END_CASE

// ================= TC10: fault injection + recovery =================
10:
    CASE stp OF
        0: // inject: unreachable gantry target (idx 99 -> y >> arm)
            ptCur := T#30S; tonG(IN := FALSE);
            GVL_Mech.fbGantry.Cmd.code := GVL_Cfg.MCMD_PLACE;
            GVL_Mech.fbGantry.Cmd.p1 := 99.0;
            GVL_Mech.fbGantry.CmdExec := FALSE;  // may be left TRUE by JobExec (TC9) — force an edge
            stp := 20;
        20: // arm on a fresh scan
            GVL_Mech.fbGantry.CmdExec := TRUE;
            stp := 1;
        1:
            IF GVL_Mech.fbGantry.Error THEN
                GVL_Mech.fbGantry.CmdExec := FALSE;
                IF (GVL_Mech.fbGantry.ErrorID AND 16#FFFF) <> TO_UDINT(GVL_Cfg.ERR_UNREACH) THEN
                    aFailCode[10] := GVL_Mech.fbGantry.ErrorID; stp := 90;
                ELSE
                    tonG(IN := FALSE); stp := 2;
                END_IF
            ELSIF tonG.Q THEN aFailCode[10] := 1; stp := 90; END_IF
        2: // system must fall to FAULT via alarm cascade
            IF GVL_Sts.mode = E_MachMode.FAULT THEN
                GVL_Cmd.reqAckAll := TRUE; holdCnt := 0;
                tonG(IN := FALSE); stp := 3;
            ELSIF tonG.Q THEN aFailCode[10] := 2; stp := 90; END_IF
        3:
            holdCnt := holdCnt + 1;
            IF holdCnt > 5 THEN
                GVL_Cmd.reqAckAll := FALSE;
                GVL_Cmd.reqReset := TRUE; holdCnt := 0;
                stp := 4;
            END_IF
        4:
            holdCnt := holdCnt + 1;
            IF holdCnt > 5 THEN GVL_Cmd.reqReset := FALSE; END_IF
            IF holdCnt > 10 THEN GVL_Cmd.reqReset := TRUE; holdCnt := 0; END_IF  // retry edge
            IF GVL_Sts.mode = E_MachMode.HOMING THEN
                GVL_Cmd.reqReset := FALSE;
                ptCur := T#90S; tonG(IN := FALSE); stp := 5;
            ELSIF tonG.Q THEN aFailCode[10] := 4; stp := 90; END_IF
        5:
            IF (GVL_Sts.mode = E_MachMode.READY) AND GVL_Sts.allHomed THEN
                tonG(IN := FALSE); stp := 6;
            ELSIF tonG.Q THEN aFailCode[10] := 5; stp := 90; END_IF
        6: // inject 2: scraper sweep with interlock FALSE
            GVL_Mech.fbScraper.InterlockOk := FALSE;
            GVL_Mech.fbScraper.Cmd.code := GVL_Cfg.MCMD_SWEEP;
            GVL_Mech.fbScraper.Cmd.p1 := 0.0;
            GVL_Mech.fbScraper.CmdExec := TRUE;
            ptCur := T#20S; tonG(IN := FALSE); stp := 7;
        7:
            IF GVL_Mech.fbScraper.Error THEN
                GVL_Mech.fbScraper.CmdExec := FALSE;
                IF (GVL_Mech.fbScraper.ErrorID AND 16#FFFF) <> TO_UDINT(GVL_Cfg.ERR_INTERLOCK) THEN
                    aFailCode[10] := GVL_Mech.fbScraper.ErrorID; stp := 90;
                ELSE
                    tonG(IN := FALSE); stp := 8;
                END_IF
            ELSIF tonG.Q THEN aFailCode[10] := 7; stp := 90; END_IF
        8: // recover again
            IF GVL_Sts.mode = E_MachMode.FAULT THEN
                GVL_Cmd.reqAckAll := TRUE; holdCnt := 0; stp := 9;
            ELSIF tonG.Q THEN aFailCode[10] := 8; stp := 90; END_IF
        9:
            holdCnt := holdCnt + 1;
            IF holdCnt > 5 THEN
                GVL_Cmd.reqAckAll := FALSE;
                GVL_Cmd.reqReset := TRUE; holdCnt := 0;
                ptCur := T#90S; tonG(IN := FALSE); stp := 11;
            END_IF
        11:
            holdCnt := holdCnt + 1;
            IF holdCnt > 5 THEN GVL_Cmd.reqReset := FALSE; END_IF
            IF (holdCnt > 10) AND (GVL_Sts.mode = E_MachMode.FAULT) THEN
                GVL_Cmd.reqReset := TRUE; holdCnt := 0;   // retry edge while still faulted
            END_IF
            IF (GVL_Sts.mode = E_MachMode.READY) AND GVL_Sts.allHomed THEN
                GVL_Cmd.reqReset := FALSE;
                aResult[10] := 1; stp := 99;
            ELSIF tonG.Q THEN aFailCode[10] := 11; stp := 90; END_IF
        90:
            GVL_Mech.fbGantry.CmdExec := FALSE;
            GVL_Mech.fbScraper.CmdExec := FALSE;
            aResult[10] := 2; stp := 99;
        99: // ---- suite complete ----
            PassCount := 0;
            FOR i := 1 TO 10 DO
                IF aResult[i] = 1 THEN PassCount := PassCount + 1; END_IF
            END_FOR
            suiteDone := TRUE; running := FALSE;
            GVL_Cmd.testStart := FALSE;
    END_CASE
END_CASE
